#[cfg(feature = "unicorn")]
fn pop_pending_guest_thread_return_for_thread(
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingGuestThreadReturn>>>,
    thread_id: u32,
) -> Option<PendingGuestThreadReturn> {
    let mut pending_returns = pending_returns.borrow_mut();
    let index = pending_returns
        .iter()
        .rposition(|pending| pending.worker_thread_id == thread_id)?;
    Some(pending_returns.remove(index))
}

#[cfg(feature = "unicorn")]
fn guest_thread_wait_owner_id(kernel: &CeKernel, thread_id: u32, thread_handle: u32) -> u32 {
    kernel.guest_thread_id(thread_handle).unwrap_or(thread_id)
}

#[cfg(feature = "unicorn")]
fn running_guest_thread_for_wait(
    kernel: &CeKernel,
    thread_id: u32,
    running_thread: &std::rc::Rc<std::cell::RefCell<Option<(u32, u32)>>>,
) -> Option<(u32, u32)> {
    running_thread.borrow().and_then(|(id, handle)| {
        (id == thread_id).then(|| {
            (
                guest_thread_wait_owner_id(kernel, thread_id, handle),
                handle,
            )
        })
    })
}

#[cfg(feature = "unicorn")]
fn pop_pending_wndproc_return_for_call_sp(
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
    call_sp: u32,
) -> Option<PendingWndProcReturn> {
    let mut pending_returns = pending_returns.borrow_mut();
    if pending_returns
        .last()
        .is_some_and(|pending| pending.return_sp.wrapping_sub(WNDPROC_CALL_FRAME_BYTES) == call_sp)
    {
        return pending_returns.pop();
    }
    let index = pending_returns
        .iter()
        .rposition(|pending| pending.return_sp.wrapping_sub(WNDPROC_CALL_FRAME_BYTES) == call_sp)?;
    Some(pending_returns.remove(index))
}

#[cfg(feature = "unicorn")]
fn snapshot_has_orphaned_cross_process_send_yield(
    snapshot: &mut Option<UnicornDebugSnapshot>,
    kernel: &CeKernel,
) -> bool {
    let Some(snapshot) = snapshot.as_mut() else {
        return false;
    };
    let Some(yielded) = snapshot.cross_process_send_yield.as_ref() else {
        return false;
    };
    if kernel.gwe.sent_message(yielded.send_id).is_some() {
        return false;
    }
    snapshot.cross_process_send_yield = None;
    true
}

