    #[cfg(feature = "unicorn")]
    fn mapped_guest_wndproc(&self, wndproc: u32) -> Option<u32> {
        if !is_guest_wndproc(wndproc) {
            return None;
        }
        if mapped_blob_module_for_pc(&self.mapped_blobs, wndproc).is_some() {
            if let Some(process_slot_wndproc) =
                Self::mapped_process_slot_dll_callback_for_shared_callback(
                    &self.mapped_blobs,
                    wndproc,
                )
            {
                return Some(process_slot_wndproc);
            }
            return Some(wndproc);
        }
        if wndproc < CE_USER_KERNEL_SPLIT {
            let slot_offset = wndproc & CE_PROCESS_SLOT_MASK;
            if let Some(dll_wndproc) =
                Self::mapped_dll_alias_callback(&self.mapped_blobs, slot_offset)
            {
                return Some(dll_wndproc);
            }
            let slot_zero_wndproc = slot_offset;
            if slot_zero_wndproc != 0
                && mapped_blob_module_for_pc(&self.mapped_blobs, slot_zero_wndproc).is_some()
            {
                return Some(slot_zero_wndproc);
            }
        }
        None
    }

    #[cfg(feature = "unicorn")]
    fn receiver_process_wndproc(&self, wndproc: u32) -> Option<u32> {
        if !is_guest_wndproc(wndproc) {
            return None;
        }
        if is_ce_high_process_slot_callback(wndproc) {
            return Some(wndproc);
        }
        self.mapped_guest_wndproc(wndproc)
    }

    #[cfg(feature = "unicorn")]
    fn mapped_dll_alias_callback(mapped_blobs: &[MappedBlob], slot_offset: u32) -> Option<u32> {
        if slot_offset == 0 {
            return None;
        }
        let mut fallback = None;
        let mut process_slot_candidate = None;
        for blob in mapped_blobs {
            if !blob.name.starts_with("dll:") {
                continue;
            }
            let Some(candidate) = blob.base.checked_add(slot_offset) else {
                continue;
            };
            let Some(offset) = candidate.checked_sub(blob.base) else {
                continue;
            };
            if offset >= blob.bytes.len() as u32 {
                continue;
            }
            if Self::mapped_dll_blob_is_process_slot_view(blob) {
                process_slot_candidate.get_or_insert(candidate);
            } else {
                fallback.get_or_insert(candidate);
            }
        }
        process_slot_candidate.or(fallback)
    }

    #[cfg(feature = "unicorn")]
    fn mapped_process_slot_dll_callback_for_shared_callback(
        mapped_blobs: &[MappedBlob],
        callback: u32,
    ) -> Option<u32> {
        let shared_blob = mapped_blobs.iter().find(|blob| {
            blob.name.starts_with("dll:")
                && blob.base >= CE_PROCESS_SLOT_SIZE
                && callback >= blob.base
                && callback.wrapping_sub(blob.base) < blob.bytes.len() as u32
        })?;
        let offset = callback.checked_sub(shared_blob.base)?;
        if offset == 0 {
            return None;
        }
        mapped_blobs.iter().find_map(|blob| {
            if !Self::mapped_dll_blob_is_process_slot_view(blob) {
                return None;
            }
            if offset >= blob.bytes.len() as u32 {
                return None;
            }
            blob.base.checked_add(offset)
        })
    }

    #[cfg(feature = "unicorn")]
    fn mapped_dll_blob_is_process_slot_view(blob: &MappedBlob) -> bool {
        blob.name.starts_with("dll:")
            && (blob.base < CE_PROCESS_SLOT_SIZE
                || mapped_blob_pe_preferred_image_base(blob)
                    .is_some_and(|base| base < CE_PROCESS_SLOT_SIZE))
    }

    #[cfg(feature = "unicorn")]
    fn thread_has_receiver_work(thread_id: u32, kernel: &CeKernel) -> bool {
        kernel.thread_has_pending_sent_message(thread_id)
            || kernel.gwe.has_message_filtered(thread_id, None, 0, 0)
    }

    #[cfg(feature = "unicorn")]
    fn has_active_blocked_state(&self, kernel: &CeKernel) -> bool {
        self.blocked_guest_thread.is_some()
            || !self.displaced_blocked_get_messages.is_empty()
            || self.blocked_modal_message_box.is_some()
            || self.blocked_popup_menu_modal.is_some()
            || self.blocked_send_message_timeout.is_some()
            || self.blocked_clipboard_data.is_some()
            || !self.blocked_wait_threads.is_empty()
            || self.running_guest_thread.is_some()
            || kernel
                .scheduler
                .blocked_waits()
                .any(|wait| self.contains_thread(&[wait.thread_id]))
    }

    #[cfg(not(feature = "unicorn"))]
    fn has_active_blocked_state(&self, _kernel: &CeKernel) -> bool {
        false
    }

    #[cfg(feature = "unicorn")]
    pub fn current_thread_id(&self) -> u32 {
        self.current_thread_id
    }

    #[cfg(feature = "unicorn")]
    pub fn rotate_to_active_visible_receiver_thread(
        &mut self,
        kernel: &CeKernel,
        target_thread_ids: &[u32],
    ) -> bool {
        let active_thread_id = self.current_thread_id;
        let Some(resume) = self
            .pop_persisted_suspended_guest_thread_matching(|thread| {
                thread.thread_id != active_thread_id
                    && (target_thread_ids.is_empty()
                        || target_thread_ids.contains(&thread.thread_id))
                    && Self::thread_has_visible_receiver_work(thread.thread_id, kernel)
            })
            .or_else(|| {
                self.pop_self_suspended_guest_thread_matching(|thread| {
                    thread.thread_id != active_thread_id
                        && (target_thread_ids.is_empty()
                            || target_thread_ids.contains(&thread.thread_id))
                        && Self::thread_has_visible_receiver_work(thread.thread_id, kernel)
                })
            })
        else {
            return false;
        };
        let Some(saved) = self.saved_context.take() else {
            self.push_persisted_suspended_guest_thread(resume);
            return false;
        };
        if !Self::saved_cpu_context_is_resumable(&saved) {
            self.saved_context = Some(saved);
            self.push_persisted_suspended_guest_thread(resume);
            return false;
        }

        let active = SuspendedGuestThread {
            thread_id: active_thread_id,
            thread_handle: self
                .running_guest_thread
                .and_then(|(id, handle)| (id == active_thread_id).then_some(handle)),
            regs: saved.regs,
            pc: saved.pc,
        };
        self.push_persisted_suspended_guest_thread(active);

        self.current_thread_id = resume.thread_id;
        self.running_guest_thread = resume
            .thread_handle
            .map(|handle| (resume.thread_id, handle));
        self.saved_context = Some(SavedCpuContext {
            pc: resume.pc,
            regs: resume.regs,
        });
        true
    }

    #[cfg(feature = "unicorn")]
    fn pop_self_suspended_guest_thread_matching(
        &mut self,
        mut predicate: impl FnMut(&SuspendedGuestThread) -> bool,
    ) -> Option<SuspendedGuestThread> {
        let thread_id = self
            .self_suspended_guest_threads
            .iter()
            .find_map(|(thread_id, thread)| predicate(thread).then_some(*thread_id))?;
        self.self_suspended_guest_threads.remove(&thread_id)
    }

    #[cfg(feature = "unicorn")]
    fn pop_persisted_suspended_guest_thread_matching(
        &mut self,
        mut predicate: impl FnMut(&SuspendedGuestThread) -> bool,
    ) -> Option<SuspendedGuestThread> {
        if self
            .suspended_guest_thread
            .as_ref()
            .is_some_and(&mut predicate)
        {
            return self.suspended_guest_thread.take();
        }
        let index = self
            .suspended_guest_thread_queue
            .iter()
            .position(predicate)?;
        self.suspended_guest_thread_queue.remove(index)
    }

    #[cfg(feature = "unicorn")]
    fn remove_persisted_suspended_guest_thread(&mut self, thread_id: u32) {
        if self
            .suspended_guest_thread
            .as_ref()
            .is_some_and(|thread| thread.thread_id == thread_id)
        {
            self.suspended_guest_thread = None;
        }
        self.suspended_guest_thread_queue
            .retain(|thread| thread.thread_id != thread_id);
    }

    #[cfg(feature = "unicorn")]
    fn push_persisted_suspended_guest_thread(&mut self, thread: SuspendedGuestThread) {
        self.remove_persisted_suspended_guest_thread(thread.thread_id);
        if self.suspended_guest_thread.is_none() {
            self.suspended_guest_thread = Some(thread);
        } else {
            self.suspended_guest_thread_queue.push_back(thread);
        }
    }

