    #[test]
    fn current_wait_comm_event_without_peer_parks_and_stops_instead_of_falling_through() {
        const EV_RXCHAR: u32 = 0x0001;
        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = crate::ce::kernel::CeKernel::boot(config);
        let com = kernel
            .create_file_w("COM7:", GENERIC_READ | GENERIC_WRITE, CREATE_ALWAYS)
            .unwrap();
        kernel.set_comm_mask(com, EV_RXCHAR).unwrap();
        assert!(!kernel.serial_comm_event_ready(com));

        let mut uc = unicorn_engine::Unicorn::new(
            unicorn_engine::Arch::MIPS,
            unicorn_engine::Mode::MIPS32 | unicorn_engine::Mode::LITTLE_ENDIAN,
        )
        .unwrap();
        let event_ptr = 0x3000_2000;
        uc.mem_map(event_ptr.into(), 0x1000, unicorn_engine::Prot::ALL)
            .unwrap();
        let thread_id = 8;
        let thread_handle = 0x808;
        let return_pc = 0x0040_8000u32;
        uc.reg_write(unicorn_engine::RegisterMIPS::RA, u64::from(return_pc))
            .unwrap();
        uc.reg_write(unicorn_engine::RegisterMIPS::S1, 0x2468_1357)
            .unwrap();

        let blocked_waits = std::rc::Rc::new(std::cell::RefCell::new(Vec::new()));
        let stale_event = kernel.create_event_w(None, true, false);
        let stale_wait_id = kernel.register_blocked_waiter(
            thread_id,
            thread_handle,
            vec![stale_event],
            crate::ce::scheduler::SchedulerBlockedWaitKind::Kernel,
            0,
            INFINITE,
        );
        blocked_waits.borrow_mut().push(BlockedWaitThread {
            wait_id: stale_wait_id,
            thread_id,
            thread_handle,
            wait_handles: vec![stale_event],
            kind: BlockedWaitKind::Kernel,
            wait_started_ms: 0,
            timeout_ms: INFINITE,
            regs: super::MipsGuestContext::zero(),
            return_pc: 0,
        });
        let pending_returns = std::rc::Rc::new(std::cell::RefCell::new(Vec::new()));
        let current_thread_id = std::rc::Rc::new(std::cell::RefCell::new(thread_id));
        let suspended_thread = std::rc::Rc::new(std::cell::RefCell::new(None));
        let running_thread =
            std::rc::Rc::new(std::cell::RefCell::new(Some((thread_id, thread_handle))));

        assert!(super::try_block_wait_comm_event(
            &mut kernel,
            &mut uc,
            crate::emulator::imports::ImportModuleKind::Coredll,
            Some(crate::ce::coredll_ordinals::ORD_WAIT_COMM_EVENT),
            &[com, event_ptr],
            thread_id,
            &blocked_waits,
            &pending_returns,
            &current_thread_id,
            &suspended_thread,
            &running_thread,
        ));

        assert_eq!(*running_thread.borrow(), None);
        assert_eq!(*current_thread_id.borrow(), thread_id);
        assert!(kernel.blocked_waiter(stale_wait_id).is_none());
        let blocked_waits = blocked_waits.borrow();
        assert_eq!(blocked_waits.len(), 1);
        let blocked = &blocked_waits[0];
        assert_eq!(blocked.thread_id, thread_id);
        assert_eq!(blocked.thread_handle, thread_handle);
        assert!(blocked.wait_handles.is_empty());
        assert!(matches!(
            blocked.kind,
            BlockedWaitKind::SerialCommEvent {
                handle,
                event_ptr: actual_event_ptr
            } if handle == com && actual_event_ptr == event_ptr
        ));
        assert!(kernel.blocked_waiter(blocked.wait_id).is_some());
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::S1).unwrap() as u32,
            0x2468_1357
        );
    }

    #[test]
    fn wait_comm_event_yields_to_ready_blocked_waiter() {
        const EV_RXCHAR: u32 = 0x0001;
        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = crate::ce::kernel::CeKernel::boot(config);
        let com = kernel
            .create_file_w("COM7:", GENERIC_READ | GENERIC_WRITE, CREATE_ALWAYS)
            .unwrap();
        kernel.set_comm_mask(com, EV_RXCHAR).unwrap();
        assert!(!kernel.serial_comm_event_ready(com));

        let mut uc = unicorn_engine::Unicorn::new(
            unicorn_engine::Arch::MIPS,
            unicorn_engine::Mode::MIPS32 | unicorn_engine::Mode::LITTLE_ENDIAN,
        )
        .unwrap();
        let event_ptr = 0x3000_2000;
        uc.mem_map(event_ptr.into(), 0x1000, unicorn_engine::Prot::ALL)
            .unwrap();
        let active_thread_id = 8;
        let active_thread_handle = 0x808;
        let active_return_pc = 0x0040_8000u32;
        uc.reg_write(
            unicorn_engine::RegisterMIPS::RA,
            u64::from(active_return_pc),
        )
        .unwrap();

        let worker_thread_id = 9;
        let worker_thread_handle = 0x909;
        let worker_return_pc = 0x0040_9000;
        let worker_event = kernel.create_event_w(None, true, true);
        let wait_started_ms = kernel.timers.tick_count();
        let worker_wait_id = kernel.register_blocked_waiter(
            worker_thread_id,
            worker_thread_handle,
            vec![worker_event],
            crate::ce::scheduler::SchedulerBlockedWaitKind::Kernel,
            wait_started_ms,
            INFINITE,
        );
        let mut worker_regs = super::MipsGuestContext::zero();
        worker_regs.regs[16] = 0x9090_0001;
        let blocked_waits = std::rc::Rc::new(std::cell::RefCell::new(vec![BlockedWaitThread {
            wait_id: worker_wait_id,
            thread_id: worker_thread_id,
            thread_handle: worker_thread_handle,
            wait_handles: vec![worker_event],
            kind: BlockedWaitKind::Kernel,
            wait_started_ms,
            timeout_ms: INFINITE,
            regs: worker_regs,
            return_pc: worker_return_pc,
        }]));
        let pending_returns = std::rc::Rc::new(std::cell::RefCell::new(Vec::new()));
        let current_thread_id = std::rc::Rc::new(std::cell::RefCell::new(active_thread_id));
        let suspended_thread = std::rc::Rc::new(std::cell::RefCell::new(None));
        let running_thread = std::rc::Rc::new(std::cell::RefCell::new(Some((
            active_thread_id,
            active_thread_handle,
        ))));

        assert!(super::try_block_wait_comm_event(
            &mut kernel,
            &mut uc,
            crate::emulator::imports::ImportModuleKind::Coredll,
            Some(crate::ce::coredll_ordinals::ORD_WAIT_COMM_EVENT),
            &[com, event_ptr],
            active_thread_id,
            &blocked_waits,
            &pending_returns,
            &current_thread_id,
            &suspended_thread,
            &running_thread,
        ));

        assert!(kernel.blocked_waiter(worker_wait_id).is_none());
        assert_eq!(*current_thread_id.borrow(), worker_thread_id);
        assert_eq!(
            *running_thread.borrow(),
            Some((worker_thread_id, worker_thread_handle))
        );
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::S0).unwrap() as u32,
            0x9090_0001
        );
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::V0).unwrap() as u32,
            WAIT_OBJECT_0
        );
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::PC).unwrap() as u32,
            worker_return_pc
        );
        let remaining = blocked_waits.borrow();
        assert_eq!(remaining.len(), 1);
        assert_eq!(remaining[0].thread_id, active_thread_id);
        assert!(matches!(
            remaining[0].kind,
            BlockedWaitKind::SerialCommEvent { handle, .. } if handle == com
        ));
        assert_eq!(remaining[0].return_pc, active_return_pc);
    }

    #[test]
    fn finite_serial_read_timeout_without_peer_completes_current_thread() {
        use unicorn_engine::RegisterMIPS;

        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = crate::ce::kernel::CeKernel::boot(config);
        let mut uc = unicorn_engine::Unicorn::new(
            unicorn_engine::Arch::MIPS,
            unicorn_engine::Mode::MIPS32 | unicorn_engine::Mode::LITTLE_ENDIAN,
        )
        .unwrap();
        uc.mem_map(0x3000_0000, 0x1000, unicorn_engine::Prot::ALL)
            .unwrap();
        let thread_id = 6;
        let thread_handle = 0x606;
        let return_pc = 0x0040_6000;
        let buffer = 0x3000_0100;
        let transferred_ptr = 0x3000_0200;
        let handle = kernel
            .create_file_w("COM7:", GENERIC_READ | GENERIC_WRITE, CREATE_ALWAYS)
            .unwrap();
        uc.reg_write(RegisterMIPS::RA, u64::from(return_pc))
            .unwrap();
        uc.reg_write(RegisterMIPS::S0, 0x1234_5678).unwrap();
        uc.mem_write(u64::from(transferred_ptr), &0xffff_ffff_u32.to_le_bytes())
            .unwrap();

        let blocked_waits = std::rc::Rc::new(std::cell::RefCell::new(Vec::new()));
        let pending_returns = std::rc::Rc::new(std::cell::RefCell::new(Vec::new()));
        let current_thread_id = std::rc::Rc::new(std::cell::RefCell::new(thread_id));
        let suspended_thread = std::rc::Rc::new(std::cell::RefCell::new(None));
        let running_thread =
            std::rc::Rc::new(std::cell::RefCell::new(Some((thread_id, thread_handle))));

        assert!(block_serial_read_file(
            &mut kernel,
            &mut uc,
            &[],
            thread_id,
            &blocked_waits,
            &pending_returns,
            &current_thread_id,
            &suspended_thread,
            &running_thread,
            handle,
            buffer,
            16,
            transferred_ptr,
            1,
        ));

        assert!(blocked_waits.borrow().is_empty());
        assert!(kernel.blocked_waiters().next().is_none());
        assert_eq!(*current_thread_id.borrow(), thread_id);
        assert_eq!(*running_thread.borrow(), Some((thread_id, thread_handle)));
        assert_eq!(uc.reg_read(RegisterMIPS::S0).unwrap() as u32, 0x1234_5678);
        assert_eq!(uc.reg_read(RegisterMIPS::V0).unwrap() as u32, 1);
        assert_eq!(uc.reg_read(RegisterMIPS::PC).unwrap() as u32, return_pc);
        assert_eq!(uc.reg_read(RegisterMIPS::RA).unwrap() as u32, return_pc);
        let mut transferred = [0; 4];
        uc.mem_read(u64::from(transferred_ptr), &mut transferred)
            .unwrap();
        assert_eq!(u32::from_le_bytes(transferred), 0);
    }

