        assert_eq!(
            kernel.process_module_path(),
            "\\SDMMC Disk\\INavi\\iNavi.exe"
        );
        assert!(
            parent
                .parked_child_processes
                .iter()
                .any(|process| process.process_state.process_id == 68)
        );

