#[cfg(feature = "unicorn")]
fn should_trace_wndproc_message(msg: u32) -> bool {
    msg >= crate::ce::gwe::WM_USER || (cfg!(feature = "trace") && is_display_lifecycle_message(msg))
}

#[cfg(feature = "unicorn")]
fn is_display_lifecycle_message(msg: u32) -> bool {
    matches!(
        msg,
        crate::ce::gwe::WM_CREATE
            | crate::ce::gwe::WM_NCCREATE
            | WM_INITDIALOG
            | crate::ce::gwe::WM_DESTROY
            | crate::ce::gwe::WM_ERASEBKGND
            | crate::ce::gwe::WM_MOVE
            | crate::ce::gwe::WM_SIZE
            | crate::ce::gwe::WM_PAINT
            | crate::ce::gwe::WM_SHOWWINDOW
            | crate::ce::gwe::WM_WINDOWPOSCHANGED
            | crate::ce::gwe::WM_NCDESTROY
            | crate::ce::gwe::WM_COMMAND
            | crate::ce::gwe::WM_TIMER
            | 0x0200
            | 0x0201
            | 0x0202
    )
}

#[cfg(feature = "unicorn")]
fn is_guest_wndproc(wndproc: u32) -> bool {
    wndproc != 0 && wndproc != crate::ce::gwe::DEFAULT_WNDPROC
}

#[cfg(feature = "unicorn")]
const CE_VA_SECTION_SHIFT: u32 = 25;
#[cfg(feature = "unicorn")]
const CE_PROCESS_SLOT_SIZE: u32 = 1 << CE_VA_SECTION_SHIFT;
#[cfg(feature = "unicorn")]
const CE_PROCESS_SLOT_MASK: u32 = CE_PROCESS_SLOT_SIZE - 1;
#[cfg(feature = "unicorn")]
const CE_SHARED_HEAP_BASE: u32 = 0x7000_0000;
#[cfg(feature = "unicorn")]
const CE_USER_KERNEL_SPLIT: u32 = 0x8000_0000;

#[cfg(feature = "unicorn")]
fn is_ce_high_process_slot_callback(callback: u32) -> bool {
    (CE_SHARED_HEAP_BASE..CE_USER_KERNEL_SPLIT).contains(&callback)
}

#[cfg(feature = "unicorn")]
fn can_read_unicorn_code<D>(uc: &unicorn_engine::Unicorn<'_, D>, address: u32) -> bool {
    let mut bytes = [0; 4];
    uc.mem_read(u64::from(address), &mut bytes).is_ok()
}

#[cfg(feature = "unicorn")]
fn normalize_ce_process_slot_callback<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    callback: u32,
) -> u32 {
    if callback < CE_PROCESS_SLOT_SIZE || callback >= CE_USER_KERNEL_SPLIT {
        return callback;
    }
    if can_read_unicorn_code(uc, callback) {
        return callback;
    }

    let slot_zero_callback = callback & CE_PROCESS_SLOT_MASK;
    if slot_zero_callback == 0 || !can_read_unicorn_code(uc, slot_zero_callback) {
        return callback;
    }

    tracing::debug!(
        target: "ce.gwe",
        callback = format_args!("0x{callback:08x}"),
        slot_zero_callback = format_args!("0x{slot_zero_callback:08x}"),
        "mapped CE process-slot callback to current process"
    );
    slot_zero_callback
}

#[cfg(feature = "unicorn")]
fn should_direct_call_send_message_wndproc(
    active_thread_id: u32,
    active_process_id: u32,
    target_thread_id: u32,
    target_process_id: u32,
    wndproc: u32,
) -> bool {
    active_thread_id == target_thread_id
        && active_process_id == target_process_id
        && is_guest_wndproc(wndproc)
}

#[cfg(feature = "unicorn")]
fn should_receiver_context_send_message_wndproc(
    active_thread_id: u32,
    active_process_id: u32,
    target_thread_id: u32,
    target_process_id: u32,
    wndproc: u32,
) -> bool {
    active_thread_id != target_thread_id
        && active_process_id == target_process_id
        && is_guest_wndproc(wndproc)
}

#[cfg(feature = "unicorn")]
fn try_enter_set_window_pos_callout<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    active_thread_id: u32,
    trampoline_jumps: &[MipsTrampolineJump],
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || ordinal != Some(crate::ce::coredll_ordinals::ORD_SET_WINDOW_POS)
    {
        return false;
    }

    let hwnd = args.first().copied().unwrap_or(0);
    let Some(window) = kernel.gwe.window(hwnd).filter(|window| !window.destroyed) else {
        return false;
    };
    let wndproc = window.wndproc;
    let target_thread_id = window.thread_id;
    let target_process_id = window.process_id;
    let class_name = window.class_name.clone();
    let active_process_id = kernel.current_process_id();
    if !should_direct_call_send_message_wndproc(
        active_thread_id,
        active_process_id,
        target_thread_id,
        target_process_id,
        wndproc,
    ) {
        return false;
    }

    let flags = args.get(6).copied().unwrap_or(0);
    if flags & (crate::ce::gwe::SWP_SHOWWINDOW | crate::ce::gwe::SWP_HIDEWINDOW) != 0 {
        return false;
    }

    let hwnd_insert_after = args.get(1).copied().unwrap_or(0);
    let x = args.get(2).copied().unwrap_or(0) as i32;
    let y = args.get(3).copied().unwrap_or(0) as i32;
    let cx = args.get(4).copied().unwrap_or(0) as i32;
    let cy = args.get(5).copied().unwrap_or(0) as i32;
    let raw_return_pc = read_mips_reg(uc, RegisterMIPS::RA);
    let return_pc = import_callout_return_pc(raw_return_pc, trampoline_jumps);
    let moved = kernel.set_window_pos(hwnd, Some(hwnd_insert_after), x, y, cx, cy, flags);
    let message = kernel.take_ready_message_w_filtered(
        active_thread_id,
        Some(hwnd),
        crate::ce::gwe::WM_WINDOWPOSCHANGED,
        crate::ce::gwe::WM_WINDOWPOSCHANGED,
    );

    let Some(message) = message else {
        kernel.threads.set_last_error(active_thread_id, 0);
        let writes = [
            uc.reg_write(RegisterMIPS::V0, u64::from(u32::from(moved))),
            uc.reg_write(RegisterMIPS::PC, u64::from(return_pc)),
            uc.reg_write(RegisterMIPS::RA, u64::from(return_pc)),
        ];
        return writes.into_iter().all(|write| write.is_ok());
    };

    let caller_regs = capture_mips_gprs(uc);
    pending_returns.borrow_mut().push(PendingWndProcReturn {
        source: "SetWindowPos/WM_WINDOWPOSCHANGED",
        hwnd: message.hwnd,
        msg: message.msg,
        wparam: message.wparam,
        lparam: message.lparam,
        wndproc,
        return_pc,
        return_sp: wndproc_return_sp(uc),
        caller_regs: Some(caller_regs),
        class_name: Some(class_name.clone()),
        api_result: Some(u32::from(moved)),
        dialog_result_hwnd: None,
        finalize_destroy: false,
        destroy_root_hwnd: None,
        remaining_destroy_callouts: Vec::new(),
        send_thread_id: None,
        send_timeout_result_ptr: None,
        send_restore: None,
        continuation: None,
        resume_import: None,
        clear_focus_after_return: None,
    });
    if write_wndproc_call_registers(
        uc,
        message.hwnd,
        message.msg,
        message.wparam,
        message.lparam,
        wndproc,
        WNDPROC_RETURN_STUB_ADDR,
    ) {
        tracing::debug!(
            target: "ce.gwe",
            hwnd = format_args!("0x{hwnd:08x}"),
            msg = format_args!("0x{:08x}", message.msg),
            lparam = format_args!("0x{:08x}", message.lparam),
            class = class_name.as_str(),
            wndproc = format_args!("0x{wndproc:08x}"),
            return_pc = format_args!("0x{return_pc:08x}"),
            "SetWindowPos guest wndproc callout"
        );
        true
    } else {
        let _ = pending_returns.borrow_mut().pop();
        false
    }
}

#[cfg(feature = "unicorn")]
fn try_enter_dispatch_message_callout<D>(
    kernel: &CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    active_thread_id: u32,
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || ordinal != Some(crate::ce::coredll_ordinals::ORD_DISPATCH_MESSAGE_W)
    {
        return false;
    }

    let msg_ptr = args.first().copied().unwrap_or(0);
    let Some(hwnd) = read_unicorn_u32(uc, msg_ptr) else {
        return false;
    };
    let Some(msg) = read_unicorn_u32(uc, msg_ptr.wrapping_add(4)) else {
        return false;
    };
    if msg == crate::ce::gwe::WM_QUIT {
        return false;
    }
    let Some(wparam) = read_unicorn_u32(uc, msg_ptr.wrapping_add(8)) else {
        return false;
    };
    let Some(lparam) = read_unicorn_u32(uc, msg_ptr.wrapping_add(12)) else {
        return false;
    };
    if msg == crate::ce::gwe::WM_TIMER && lparam != 0 && is_guest_wndproc(lparam) {
        let return_pc = read_mips_reg(uc, RegisterMIPS::RA);
        tracing::debug!(
            target: "ce.gwe",
            msg_ptr = format_args!("0x{msg_ptr:08x}"),
            hwnd = format_args!("0x{hwnd:08x}"),
            wparam = format_args!("0x{wparam:08x}"),
            callback = format_args!("0x{lparam:08x}"),
            ra = format_args!("0x{return_pc:08x}"),
            "DispatchMessageW timer callback callout"
        );
        pending_returns.borrow_mut().push(PendingWndProcReturn {
            source: "DispatchMessageW/TimerProc",
            hwnd,
            msg,
            wparam,
            lparam,
            wndproc: lparam,
            return_pc,
            return_sp: wndproc_return_sp(uc),
            caller_regs: None,
            class_name: None,
            api_result: Some(0),
            dialog_result_hwnd: None,
            finalize_destroy: false,
            destroy_root_hwnd: None,
            remaining_destroy_callouts: Vec::new(),
            send_thread_id: None,
            send_timeout_result_ptr: None,
            send_restore: None,
            continuation: None,
            resume_import: None,
            clear_focus_after_return: None,
        });
        if write_wndproc_call_registers(
            uc,
            hwnd,
            msg,
            wparam,
            kernel.timers.tick_count(),
            lparam,
            WNDPROC_RETURN_STUB_ADDR,
        ) {
            return true;
        }
        let _ = pending_returns.borrow_mut().pop();
        return false;
    }
    let Some(window) = kernel.gwe.window(hwnd).filter(|window| !window.destroyed) else {
        return false;
    };
    let wndproc = window.wndproc;
    if !is_guest_wndproc(wndproc) {
        return false;
    }
    let return_pc = read_mips_reg(uc, RegisterMIPS::RA);

    tracing::debug!(
        target: "ce.gwe",
        msg_ptr = format_args!("0x{msg_ptr:08x}"),
        hwnd = format_args!("0x{hwnd:08x}"),
        msg = format_args!("0x{msg:08x}"),
        wparam = format_args!("0x{wparam:08x}"),
        lparam = format_args!("0x{lparam:08x}"),
        class = window.class_name.as_str(),
        wndproc = format_args!("0x{wndproc:08x}"),
        ra = format_args!("0x{return_pc:08x}"),
        "DispatchMessageW guest wndproc callout"
    );

    pending_returns.borrow_mut().push(PendingWndProcReturn {
        source: "DispatchMessageW",
        hwnd,
        msg,
        wparam,
        lparam,
        wndproc,
        return_pc,
        return_sp: wndproc_return_sp(uc),
        caller_regs: None,
        class_name: Some(window.class_name.clone()),
        api_result: None,
        dialog_result_hwnd: None,
        finalize_destroy: false,
        destroy_root_hwnd: None,
        remaining_destroy_callouts: Vec::new(),
        send_thread_id: kernel
            .gwe
            .in_send_message(active_thread_id)
            .then_some(active_thread_id),
        send_timeout_result_ptr: None,
        send_restore: None,
        continuation: None,
        resume_import: None,
        clear_focus_after_return: None,
    });
    if write_wndproc_call_registers(
        uc,
        hwnd,
        msg,
        wparam,
        lparam,
        wndproc,
        WNDPROC_RETURN_STUB_ADDR,
    ) {
        true
    } else {
        let _ = pending_returns.borrow_mut().pop();
        false
    }
}

#[cfg(feature = "unicorn")]
fn try_enter_send_message_callout<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    active_thread_id: u32,
    trampoline_jumps: &[MipsTrampolineJump],
    current_thread_id: &std::rc::Rc<std::cell::RefCell<u32>>,
    running_thread: &std::rc::Rc<std::cell::RefCell<Option<(u32, u32)>>>,
    blocked_waits: &std::rc::Rc<std::cell::RefCell<Vec<BlockedWaitThread>>>,
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
    parked_child_processes: &std::rc::Rc<std::cell::RefCell<VecDeque<ParkedProcess>>>,
    cross_process_send_yield: &std::rc::Rc<
        std::cell::RefCell<Option<UnicornCrossProcessSendYield>>,
    >,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    let is_send_message = ordinal == Some(crate::ce::coredll_ordinals::ORD_SEND_MESSAGE_W);
    let is_send_message_timeout =
        ordinal == Some(crate::ce::coredll_ordinals::ORD_SEND_MESSAGE_TIMEOUT);
    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || (!is_send_message && !is_send_message_timeout)
    {
        return false;
    }

    let hwnd = args.first().copied().unwrap_or(0);
    if !kernel.gwe.is_window(hwnd) {
        return false;
    }
    let Some(window) = kernel.gwe.window(hwnd) else {
        return false;
    };
    let wndproc = window.wndproc;
    let target_thread_id = window.thread_id;
    let target_process_id = window.process_id;
    let class_name = window.class_name.clone();
    let active_process_id = kernel.current_process_id();
    let msg = args.get(1).copied().unwrap_or(0);
    let wparam = args.get(2).copied().unwrap_or(0);
    let lparam = args.get(3).copied().unwrap_or(0);
    let result_ptr = is_send_message_timeout
        .then(|| args.get(6).copied().unwrap_or(0))
        .filter(|ptr| *ptr != 0);
    let raw_return_pc = read_mips_reg(uc, RegisterMIPS::RA);
    let return_pc = import_callout_return_pc(raw_return_pc, trampoline_jumps);
    let source = if is_send_message_timeout {
        "SendMessageTimeout"
    } else {
        "SendMessageW"
    };

    let should_direct = should_direct_call_send_message_wndproc(
        active_thread_id,
        active_process_id,
        target_thread_id,
        target_process_id,
        wndproc,
    );
    let should_receiver_context = should_receiver_context_send_message_wndproc(
        active_thread_id,
        active_process_id,
        target_thread_id,
        target_process_id,
        wndproc,
    );
    if !should_direct && !should_receiver_context {
        if active_process_id != target_process_id
            && is_guest_wndproc(wndproc)
            && parked_child_processes
                .borrow()
                .iter()
                .any(|process| process.process_state.process_id == target_process_id)
        {
            let timeout_ms = is_send_message_timeout.then(|| args.get(5).copied().unwrap_or(0));
            let Some(send_id) = kernel.begin_cross_thread_send_message_w(
                active_thread_id,
                hwnd,
                msg,
                wparam,
                lparam,
                timeout_ms,
            ) else {
                return false;
            };
            let sender_regs = capture_mips_gprs(uc);
            let previous_running_thread = *running_thread.borrow();
            let thread_handle = guest_thread_handle_for_running_context(
                kernel,
                previous_running_thread,
                active_thread_id,
            );
            let wait_started_ms = kernel.timers.tick_count();
            let timeout_for_wait = timeout_ms.unwrap_or(crate::ce::timer::INFINITE);
            let kind = BlockedWaitKind::SendMessage {
                send_id,
                receiver_thread_id: target_thread_id,
                result_ptr,
                previous_running_thread,
            };
            let wait_id = kernel.register_blocked_waiter(
                active_thread_id,
                thread_handle,
                Vec::new(),
                scheduler_blocked_wait_kind(kind),
                wait_started_ms,
                timeout_for_wait,
            );
            blocked_waits.borrow_mut().push(BlockedWaitThread {
                wait_id,
                thread_id: active_thread_id,
                thread_handle,
                wait_handles: Vec::new(),
                kind,
                wait_started_ms,
                timeout_ms: timeout_for_wait,
                regs: sender_regs,
                return_pc,
            });
            kernel.threads.set_last_error(active_thread_id, 0);
            *cross_process_send_yield.borrow_mut() = Some(UnicornCrossProcessSendYield {
                send_id,
                sender_thread_id: active_thread_id,
                sender_process_id: active_process_id,
                target_thread_id,
                target_process_id,
                hwnd,
                msg,
            });
            let writes = [
                uc.reg_write(RegisterMIPS::V0, 0),
                uc.reg_write(RegisterMIPS::PC, u64::from(return_pc)),
                uc.reg_write(RegisterMIPS::RA, u64::from(return_pc)),
            ];
            if !writes.into_iter().all(|write| write.is_ok()) {
                return false;
            }
            tracing::debug!(
                target: "ce.gwe",
                source,
                hwnd = format_args!("0x{hwnd:08x}"),
                msg = format_args!("0x{msg:08x}"),
                sender_thread_id = active_thread_id,
                sender_process_id = active_process_id,
                target_thread_id,
                target_process_id,
                "SendMessage queued cross-process send and yielded CPU"
            );
            let _ = uc.emu_stop();
            return true;
        }
        if is_guest_wndproc(wndproc) {
            if active_process_id != target_process_id {
                let result = 0u32;
                if let Some(ptr) = result_ptr {
                    let _ = uc.mem_write(u64::from(ptr), &result.to_le_bytes());
                }
                kernel.threads.set_last_error(active_thread_id, 0);
                let _ = uc.reg_write(RegisterMIPS::V0, u64::from(result));
                tracing::debug!(
                    target: "ce.gwe",
                    source,
                    hwnd = format_args!("0x{hwnd:08x}"),
                    class = class_name.as_str(),
                    wndproc = format_args!("0x{wndproc:08x}"),
                    active_thread_id,
                    active_process_id,
                    target_thread_id,
                    target_process_id,
                    "SendMessage guest wndproc target has no runnable process"
                );
                return true;
            }
            tracing::debug!(
                target: "ce.gwe",
                source,
                hwnd = format_args!("0x{hwnd:08x}"),
                class = class_name.as_str(),
                wndproc = format_args!("0x{wndproc:08x}"),
                active_thread_id,
                active_process_id,
                target_thread_id,
                target_process_id,
                "SendMessage guest wndproc not entered"
            );
            return false;
        }
        // Non-guest wndproc (DEFAULT_WNDPROC or null): dispatch synchronously.
        // These are kernel-owned windows backed by pure host Rust code; no MIPS
        // execution is needed and the dispatch is safe from any thread context.
        let result = kernel
            .send_message_w(hwnd, msg, wparam, lparam)
            .unwrap_or(0);
        if let Some(ptr) = result_ptr {
            let _ = uc.mem_write(u64::from(ptr), &result.to_le_bytes());
        }
        kernel.threads.set_last_error(active_thread_id, 0);
        let _ = uc.reg_write(RegisterMIPS::V0, u64::from(result));
        tracing::debug!(
            target: "ce.gwe",
            source,
            hwnd = format_args!("0x{hwnd:08x}"),
            class = class_name.as_str(),
            msg = format_args!("0x{msg:08x}"),
            result,
            "SendMessage non-guest wndproc dispatched directly"
        );
        return true;
    }

    tracing::debug!(
        target: "ce.gwe",
        source,
        hwnd = format_args!("0x{hwnd:08x}"),
        msg = format_args!("0x{msg:08x}"),
        wparam = format_args!("0x{wparam:08x}"),
        lparam = format_args!("0x{lparam:08x}"),
        class = window.class_name.as_str(),
        wndproc = format_args!("0x{wndproc:08x}"),
        ra = format_args!("0x{return_pc:08x}"),
        "SendMessage guest wndproc callout"
    );

    let send_restore = if should_receiver_context {
        let timeout_ms = is_send_message_timeout.then(|| args.get(5).copied().unwrap_or(0));
        let Some(send_id) = kernel.begin_cross_thread_send_message_w(
            active_thread_id,
            hwnd,
            msg,
            wparam,
            lparam,
            timeout_ms,
        ) else {
            return false;
        };
        if !kernel
            .gwe
            .activate_sent_message_for_receiver(target_thread_id, send_id)
        {
            return false;
        }
        let sender_regs = capture_mips_gprs(uc);
        let previous_running_thread = *running_thread.borrow();
        let thread_handle = guest_thread_handle_for_running_context(
            kernel,
            previous_running_thread,
            active_thread_id,
        );
        let wait_started_ms = kernel.timers.tick_count();
        let timeout_for_wait = timeout_ms.unwrap_or(crate::ce::timer::INFINITE);
        let kind = BlockedWaitKind::SendMessage {
            send_id,
            receiver_thread_id: target_thread_id,
            result_ptr,
            previous_running_thread,
        };
        let wait_id = kernel.register_blocked_waiter(
            active_thread_id,
            thread_handle,
            Vec::new(),
            scheduler_blocked_wait_kind(kind),
            wait_started_ms,
            timeout_for_wait,
        );
        blocked_waits.borrow_mut().push(BlockedWaitThread {
            wait_id,
            thread_id: active_thread_id,
            thread_handle,
            wait_handles: Vec::new(),
            kind,
            wait_started_ms,
            timeout_ms: timeout_for_wait,
            regs: sender_regs,
            return_pc,
        });
        *current_thread_id.borrow_mut() = target_thread_id;
        let _ = update_user_kdata_current_ids(uc, target_thread_id, kernel.current_process_id());
        *running_thread.borrow_mut() = kernel
            .guest_thread_handle_by_id(target_thread_id)
            .map(|handle| (target_thread_id, handle));
        Some(SendMessageRestoreContext {
            sender_thread_id: active_thread_id,
            receiver_thread_id: target_thread_id,
            send_id,
            wait_id,
        })
    } else {
        kernel.gwe.begin_send_message(target_thread_id);
        None
    };

    let has_send_restore = send_restore.is_some();
    let return_sp = wndproc_return_sp(uc);
    pending_returns.borrow_mut().push(PendingWndProcReturn {
        source,
        hwnd,
        msg,
        wparam,
        lparam,
        wndproc,
        return_pc,
        return_sp,
        caller_regs: should_direct.then(|| capture_mips_gprs(uc)),
        class_name: Some(class_name),
        api_result: None,
        dialog_result_hwnd: None,
        finalize_destroy: false,
        destroy_root_hwnd: None,
        remaining_destroy_callouts: Vec::new(),
        send_thread_id: should_direct.then_some(target_thread_id),
        send_timeout_result_ptr: result_ptr,
        send_restore,
        continuation: None,
        resume_import: None,
        clear_focus_after_return: None,
    });
    tracing::debug!(
        target: "ce.gwe",
        source,
        hwnd = format_args!("0x{hwnd:08x}"),
        msg = format_args!("0x{msg:08x}"),
        wndproc = format_args!("0x{wndproc:08x}"),
        return_pc = format_args!("0x{return_pc:08x}"),
        return_sp = format_args!("0x{return_sp:08x}"),
        call_sp = format_args!(
            "0x{:08x}",
            return_sp.wrapping_sub(WNDPROC_CALL_FRAME_BYTES)
        ),
        active_thread_id,
        target_thread_id,
        should_direct,
        should_receiver_context,
        has_send_restore,
        pending_wndproc_returns = pending_returns.borrow().len(),
        "pushed SendMessage WNDPROC callout"
    );
    if write_wndproc_call_registers(
        uc,
        hwnd,
        msg,
        wparam,
        lparam,
        wndproc,
        WNDPROC_RETURN_STUB_ADDR,
    ) {
        true
    } else {
        if let Some(callout) = pending_returns.borrow_mut().pop() {
            if let Some(restore) = callout.send_restore {
                let _ = kernel.complete_active_sent_message(restore.receiver_thread_id, 0);
                let _ = kernel.take_completed_send_message_result(restore.send_id);
                if let Some(index) = blocked_waits
                    .borrow()
                    .iter()
                    .position(|blocked| blocked.wait_id == restore.wait_id)
                {
                    let blocked = blocked_waits.borrow_mut().remove(index);
                    let _ = kernel.remove_blocked_waiter(blocked.wait_id);
                    let previous_running_thread = match blocked.kind {
                        BlockedWaitKind::SendMessage {
                            previous_running_thread,
                            ..
                        } => previous_running_thread,
                        _ => None,
                    };
                    restore_mips_gprs(uc, &blocked.regs);
                    *running_thread.borrow_mut() = previous_running_thread
                        .or_else(|| blocked_running_thread(kernel, &blocked));
                }
                *current_thread_id.borrow_mut() = restore.sender_thread_id;
                let _ = update_user_kdata_current_ids(
                    uc,
                    restore.sender_thread_id,
                    kernel.current_process_id(),
                );
            } else if let Some(thread_id) = callout.send_thread_id {
                kernel.gwe.end_send_message(thread_id);
            }
        }
        false
    }
}

#[cfg(feature = "unicorn")]
fn import_callout_return_pc(raw_return_pc: u32, trampoline_jumps: &[MipsTrampolineJump]) -> u32 {
    let trampoline_jump_index = MipsTrampolineJumpIndex::new(trampoline_jumps);
    import_callout_return_pc_indexed(raw_return_pc, &trampoline_jump_index)
}

#[cfg(feature = "unicorn")]
fn import_callout_return_pc_indexed(
    raw_return_pc: u32,
    trampoline_jump_index: &MipsTrampolineJumpIndex,
) -> u32 {
    trampoline_jump_index
        .origin_for_pc(raw_return_pc)
        .unwrap_or(raw_return_pc)
}

#[cfg(feature = "unicorn")]
fn wall_clock_restart_pc_for_mips_trampoline(
    pc: u32,
    trampoline_jumps: &[MipsTrampolineJump],
    read_u32: impl Fn(u32) -> Option<u32>,
) -> Option<u32> {
    let trampoline_index = MipsTrampolineJumpIndex::new(trampoline_jumps);
    wall_clock_restart_pc_for_mips_trampoline_indexed(pc, &trampoline_index, read_u32)
}

#[cfg(feature = "unicorn")]
fn wall_clock_restart_pc_for_mips_trampoline_indexed(
    pc: u32,
    trampoline_jump_index: &MipsTrampolineJumpIndex,
    read_u32: impl Fn(u32) -> Option<u32>,
) -> Option<u32> {
    let trampoline = trampoline_jump_index.jump_for_pc(pc)?;
    let offset = pc.wrapping_sub(trampoline.stub);
    if offset <= 8 {
        return Some(trampoline.origin);
    }

    let instruction = read_u32(pc)?;
    if let Some(target) = decode_direct_jump_target(pc, instruction) {
        return Some(target);
    }

    let next_instruction = read_u32(pc.wrapping_add(4))?;
    let jump_instruction = read_u32(pc.wrapping_add(8))?;
    let delay_slot = read_u32(pc.wrapping_add(12))?;
    decode_trampoline_long_jump_target(instruction, next_instruction, jump_instruction, delay_slot)
}

#[cfg(feature = "unicorn")]
fn import_trap_target_for_mips_jr_thunk<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    traps: &ImportTrapTable,
    pc: u32,
) -> Option<u32> {
    let target = import_trap_page_target_for_mips_jr_thunk(uc, pc)?;
    (traps.trap_at(target).is_some()
        || crate::emulator::imports::dynamic_coredll_proc_trap(target).is_some())
    .then_some(target)
}

#[cfg(feature = "unicorn")]
fn import_trap_pc(pc: u32) -> bool {
    let import_page_end = IMPORT_TRAP_BASE.saturating_add(IMPORT_TRAP_PAGE_SIZE);
    pc >= IMPORT_TRAP_BASE
        && pc < import_page_end
        && (pc - IMPORT_TRAP_BASE) % crate::emulator::imports::IMPORT_TRAP_STRIDE == 0
}

#[cfg(feature = "unicorn")]
fn import_trap_page_target_for_mips_jr_thunk<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    pc: u32,
) -> Option<u32> {
    if pc >= IMPORT_TRAP_BASE {
        return None;
    }
    let instruction = read_unicorn_u32(uc, pc)?;
    let register = decode_jr_register(instruction)?;
    if read_unicorn_u32(uc, pc.wrapping_add(4))? != MIPS_NOP {
        return None;
    }
    let target = read_mips_gpr(uc, register)?;
    let import_page_end = IMPORT_TRAP_BASE.saturating_add(IMPORT_TRAP_PAGE_SIZE);
    (target >= IMPORT_TRAP_BASE
        && target < import_page_end
        && (target - IMPORT_TRAP_BASE) % crate::emulator::imports::IMPORT_TRAP_STRIDE == 0)
        .then_some(target)
}

#[cfg(feature = "unicorn")]
fn try_enter_def_window_proc_callout<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || ordinal != Some(crate::ce::coredll_ordinals::ORD_DEF_WINDOW_PROC_W)
    {
        return false;
    }

    let hwnd = args.first().copied().unwrap_or(0);
    let msg = args.get(1).copied().unwrap_or(0);
    let wparam = args.get(2).copied().unwrap_or(0);
    let lparam = args.get(3).copied().unwrap_or(0);
    if msg == crate::ce::gwe::WM_CLOSE {
        return enter_destroy_window_wm_destroy_callout(
            kernel,
            uc,
            hwnd,
            "DefWindowProcW/WM_CLOSE",
            0,
            None,
            pending_returns,
        );
    }

    let result = default_window_proc_result(&mut kernel.gwe, hwnd, msg, wparam, lparam);
    let _ = uc.reg_write(RegisterMIPS::V0, u64::from(result));
    true
}

#[cfg(feature = "unicorn")]
fn default_window_proc_result(
    gwe: &mut crate::ce::gwe::Gwe,
    hwnd: u32,
    msg: u32,
    wparam: u32,
    lparam: u32,
) -> u32 {
    if msg == crate::ce::gwe::WM_PAINT {
        let _ = gwe.validate_window(hwnd);
    }
    if msg == crate::ce::gwe::WM_NCHITTEST {
        if let Some(window) = gwe.window(hwnd) {
            return crate::ce::gwe::default_window_hit_test(
                window.rect,
                window.client_rect,
                lparam,
            );
        }
    }
    // DefWindowProc non-client return contract (mirrors `Gwe::send_message`): these
    // must report success/handled or window creation and activation break. In
    // particular `WM_NCCREATE` must return TRUE or `CreateWindowEx` aborts the
    // window, which previously stalled MFC apps that chain to `DefWindowProcW`.
    match msg {
        crate::ce::gwe::WM_NCCREATE | crate::ce::gwe::WM_NCACTIVATE => return 1,
        crate::ce::gwe::WM_MOUSEACTIVATE => return crate::ce::gwe::MA_ACTIVATE,
        _ => {}
    }
    crate::ce::gwe::default_send_message_result(msg, wparam, lparam)
}

#[cfg(feature = "unicorn")]
fn try_enter_def_dlg_proc_callout<D>(
    kernel: &CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || ordinal != Some(crate::ce::coredll_ordinals::ORD_DEF_DLG_PROC_W)
    {
        return false;
    }

    let hwnd = args.first().copied().unwrap_or(0);
    let dlgproc = kernel
        .gwe
        .get_window_long(hwnd, crate::ce::gwe::DWL_DLGPROC)
        .unwrap_or(0);
    if !is_guest_wndproc(dlgproc) {
        return false;
    }
    let msg = args.get(1).copied().unwrap_or(0);
    let wparam = args.get(2).copied().unwrap_or(0);
    let lparam = args.get(3).copied().unwrap_or(0);
    let class_name = kernel
        .gwe
        .window(hwnd)
        .map(|window| window.class_name.clone());
    let return_pc = read_mips_reg(uc, RegisterMIPS::RA);

    tracing::debug!(
        target: "ce.gwe",
        hwnd = format_args!("0x{hwnd:08x}"),
        msg = format_args!("0x{msg:08x}"),
        wparam = format_args!("0x{wparam:08x}"),
        lparam = format_args!("0x{lparam:08x}"),
        dlgproc = format_args!("0x{dlgproc:08x}"),
        ra = format_args!("0x{return_pc:08x}"),
        "DefDlgProcW guest dlgproc callout"
    );

    pending_returns.borrow_mut().push(PendingWndProcReturn {
        source: "DefDlgProcW",
        hwnd,
        msg,
        wparam,
        lparam,
        wndproc: dlgproc,
        return_pc,
        return_sp: wndproc_return_sp(uc),
        caller_regs: None,
        class_name,
        api_result: None,
        dialog_result_hwnd: None,
        finalize_destroy: false,
        destroy_root_hwnd: None,
        remaining_destroy_callouts: Vec::new(),
        send_thread_id: None,
        send_timeout_result_ptr: None,
        send_restore: None,
        continuation: None,
        resume_import: None,
        clear_focus_after_return: None,
    });
    if write_wndproc_call_registers(
        uc,
        hwnd,
        msg,
        wparam,
        lparam,
        dlgproc,
        WNDPROC_RETURN_STUB_ADDR,
    ) {
        true
    } else {
        let _ = pending_returns.borrow_mut().pop();
        false
    }
}

#[cfg(feature = "unicorn")]
fn try_enter_enable_window_callout<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || ordinal != Some(crate::ce::coredll_ordinals::ORD_ENABLE_WINDOW)
    {
        return false;
    }

    let hwnd = args.first().copied().unwrap_or(0);
    let enabled = args.get(1).copied().unwrap_or(0) != 0;
    let Some((was_enabled, changed)) = kernel.set_window_enabled_state(hwnd, enabled) else {
        let _ = uc.reg_write(RegisterMIPS::V0, 0);
        return true;
    };
    if !changed {
        let _ = uc.reg_write(RegisterMIPS::V0, u64::from(u32::from(was_enabled)));
        return true;
    }

    let Some(window) = kernel.gwe.window(hwnd) else {
        let _ = uc.reg_write(RegisterMIPS::V0, u64::from(u32::from(was_enabled)));
        return true;
    };
    let wndproc = window.wndproc;
    if !is_guest_wndproc(wndproc) {
        if !enabled {
            kernel.clear_focus_and_activation_within(hwnd);
        }
        let _ = uc.reg_write(RegisterMIPS::V0, u64::from(u32::from(was_enabled)));
        return true;
    }

    let (source, msg, wparam, lparam, continuation) = if enabled {
        (
            "EnableWindow/WM_ENABLE",
            crate::ce::gwe::WM_ENABLE,
            1,
            0,
            None,
        )
    } else {
        (
            "EnableWindow/WM_CANCELMODE",
            crate::ce::gwe::WM_CANCELMODE,
            0,
            0,
            Some(WndProcContinuation {
                source: "EnableWindow/WM_ENABLE",
                msg: crate::ce::gwe::WM_ENABLE,
                wparam: 0,
                lparam: 0,
                clear_focus_after_return: Some(hwnd),
            }),
        )
    };
    let return_pc = read_mips_reg(uc, RegisterMIPS::RA);
    tracing::debug!(
        target: "ce.gwe",
        hwnd = format_args!("0x{hwnd:08x}"),
        enabled,
        previous = was_enabled,
        msg = format_args!("0x{msg:08x}"),
        class = window.class_name.as_str(),
        wndproc = format_args!("0x{wndproc:08x}"),
        ra = format_args!("0x{return_pc:08x}"),
        "EnableWindow guest wndproc callout"
    );

    pending_returns.borrow_mut().push(PendingWndProcReturn {
        source,
        hwnd,
        msg,
        wparam,
        lparam,
        wndproc,
        return_pc,
        return_sp: wndproc_return_sp(uc),
        caller_regs: None,
        class_name: Some(window.class_name.clone()),
        api_result: Some(u32::from(was_enabled)),
        dialog_result_hwnd: None,
        finalize_destroy: false,
        destroy_root_hwnd: None,
        remaining_destroy_callouts: Vec::new(),
        send_thread_id: None,
        send_timeout_result_ptr: None,
        send_restore: None,
        continuation,
        resume_import: None,
        clear_focus_after_return: None,
    });
    if write_wndproc_call_registers(
        uc,
        hwnd,
        msg,
        wparam,
        lparam,
        wndproc,
        WNDPROC_RETURN_STUB_ADDR,
    ) {
        true
    } else {
        let _ = pending_returns.borrow_mut().pop();
        false
    }
}

#[cfg(feature = "unicorn")]
fn try_enter_destroy_window_callout<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    framebuffer: Option<&mut dyn Framebuffer>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
) -> bool {
    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || ordinal != Some(crate::ce::coredll_ordinals::ORD_DESTROY_WINDOW)
    {
        return false;
    }

    let hwnd = args.first().copied().unwrap_or(0);
    enter_destroy_window_wm_destroy_callout(
        kernel,
        uc,
        hwnd,
        "DestroyWindow/WM_DESTROY",
        1,
        framebuffer,
        pending_returns,
    )
}

#[cfg(feature = "unicorn")]
fn enter_destroy_window_wm_destroy_callout<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    hwnd: u32,
    source: &'static str,
    api_result: u32,
    framebuffer: Option<&mut dyn Framebuffer>,
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingWndProcReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    let return_pc = read_mips_reg(uc, RegisterMIPS::RA);
    let thread_id = kernel
        .gwe
        .window(hwnd)
        .map(|window| window.thread_id)
        .unwrap_or(0);
    kernel.record_window_lifecycle_trace(
        "destroy_window_callout",
        thread_id,
        Some(hwnd),
        Some(api_result),
        Some(format!("source={source}/return_pc=0x{return_pc:08x}")),
    );
    if kernel.gwe.is_window_being_destroyed(hwnd) {
        let writes = [
            uc.reg_write(RegisterMIPS::V0, u64::from(api_result)),
            uc.reg_write(RegisterMIPS::PC, u64::from(return_pc)),
            uc.reg_write(RegisterMIPS::RA, u64::from(return_pc)),
        ];
        if writes.into_iter().any(|write| write.is_err()) {
            let _ = uc.emu_stop();
        }
        return true;
    }

    let Some(mut callouts) = collect_destroy_wndproc_callouts(kernel, hwnd) else {
        return false;
    };
    if callouts.is_empty() {
        let destroyed = kernel.destroy_window_with_framebuffer(hwnd, source, framebuffer);
        let result = if api_result == 0 {
            0
        } else {
            u32::from(destroyed)
        };
        let writes = [
            uc.reg_write(RegisterMIPS::V0, u64::from(result)),
            uc.reg_write(RegisterMIPS::PC, u64::from(return_pc)),
            uc.reg_write(RegisterMIPS::RA, u64::from(return_pc)),
        ];
        if writes.into_iter().any(|write| write.is_err()) {
            let _ = uc.emu_stop();
        }
        return true;
    }

    let first = callouts.remove(0);
    tracing::debug!(
        target: "ce.gwe",
        hwnd = format_args!("0x{:08x}", first.hwnd),
        root = format_args!("0x{hwnd:08x}"),
        remaining = callouts.len(),
        wndproc = format_args!("0x{:08x}", first.wndproc),
        ra = format_args!("0x{return_pc:08x}"),
        "DestroyWindow guest WM_DESTROY callout"
    );

    pending_returns.borrow_mut().push(PendingWndProcReturn {
        source,
        hwnd: first.hwnd,
        msg: crate::ce::gwe::WM_DESTROY,
        wparam: 0,
        lparam: 0,
        wndproc: first.wndproc,
        return_pc,
        return_sp: wndproc_return_sp(uc),
        caller_regs: None,
        class_name: first.class_name,
        api_result: Some(api_result),
        dialog_result_hwnd: None,
        finalize_destroy: true,
        destroy_root_hwnd: Some(hwnd),
        remaining_destroy_callouts: callouts,
        send_thread_id: None,
        send_timeout_result_ptr: None,
        send_restore: None,
        continuation: None,
        resume_import: None,
        clear_focus_after_return: None,
    });
    if write_wndproc_call_registers(
        uc,
        first.hwnd,
        crate::ce::gwe::WM_DESTROY,
        0,
        0,
        first.wndproc,
        WNDPROC_RETURN_STUB_ADDR,
    ) {
        true
    } else {
        let _ = pending_returns.borrow_mut().pop();
        false
    }
}

#[cfg(feature = "unicorn")]
fn collect_destroy_wndproc_callouts(
    kernel: &mut CeKernel,
    hwnd: u32,
) -> Option<Vec<DestroyWndProcCallout>> {
    let targets = kernel.gwe.window_and_descendants(hwnd)?;
    let _ = kernel.gwe.mark_window_subtree_being_destroyed(hwnd);
    let mut callouts = Vec::new();
    for target in targets.into_iter().rev() {
        let Some(window) = kernel.gwe.window(target) else {
            continue;
        };
        if window.destroyed || window.destroy_message_sent {
            continue;
        }
        let wndproc = window.wndproc;
        let class_name = Some(window.class_name.clone());
        if is_guest_wndproc(wndproc) {
            callouts.push(DestroyWndProcCallout {
                hwnd: target,
                wndproc,
                class_name,
            });
        } else {
            let _ = kernel
                .gwe
                .record_destroy_lifecycle_message(target, crate::ce::gwe::WM_DESTROY);
        }
    }
    Some(callouts)
}

#[cfg(feature = "unicorn")]
fn write_wndproc_call_registers<D>(
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    hwnd: u32,
    msg: u32,
    wparam: u32,
    lparam: u32,
    wndproc: u32,
    return_stub: u32,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    let call_wndproc = normalize_ce_process_slot_callback(uc, wndproc);
    let return_sp = read_mips_reg(uc, RegisterMIPS::SP);
    let call_sp = return_sp.wrapping_sub(WNDPROC_CALL_FRAME_BYTES);
    [
        uc.reg_write(RegisterMIPS::SP, u64::from(call_sp)),
        uc.reg_write(RegisterMIPS::A0, u64::from(hwnd)),
        uc.reg_write(RegisterMIPS::A1, u64::from(msg)),
        uc.reg_write(RegisterMIPS::A2, u64::from(wparam)),
        uc.reg_write(RegisterMIPS::A3, u64::from(lparam)),
        uc.reg_write(RegisterMIPS::RA, u64::from(return_stub)),
        uc.reg_write(RegisterMIPS::T9, u64::from(call_wndproc)),
        uc.reg_write(RegisterMIPS::PC, u64::from(call_wndproc)),
    ]
    .into_iter()
    .all(|write| write.is_ok())
}

#[cfg(feature = "unicorn")]
fn try_enter_qsort_callout<D>(
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    args: &[u32],
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingQsortReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll
        || ordinal != Some(crate::ce::coredll_ordinals::ORD_QSORT)
    {
        return false;
    }
    let base = args.first().copied().unwrap_or(0);
    let count = args.get(1).copied().unwrap_or(0);
    let size = args.get(2).copied().unwrap_or(0);
    let comparator = args.get(3).copied().unwrap_or(0);
    let return_pc = read_mips_reg(uc, RegisterMIPS::RA);
    if base == 0 || count < 2 || size == 0 || !is_guest_wndproc(comparator) {
        let writes = [
            uc.reg_write(RegisterMIPS::V0, 0),
            uc.reg_write(RegisterMIPS::PC, u64::from(return_pc)),
            uc.reg_write(RegisterMIPS::RA, u64::from(return_pc)),
        ];
        return writes.into_iter().all(|write| write.is_ok());
    }
    if count > 4096 || size > 1024 * 1024 {
        return false;
    }
    let mut state = PendingQsortReturn {
        return_pc,
        return_sp: read_mips_reg(uc, RegisterMIPS::SP),
        caller_regs: capture_mips_gprs(uc),
        base,
        count,
        size,
        comparator,
        ranges: vec![(0, count - 1)],
        partition: None,
        current_pair: None,
        deref_args: false,
        compare_lparam: None,
        finish_v0: 0,
    };
    tracing::debug!(
        target: "ce.crt",
        base = format_args!("0x{base:08x}"),
        count,
        size,
        comparator = format_args!("0x{comparator:08x}"),
        return_pc = format_args!("0x{return_pc:08x}"),
        "qsort guest comparator callout"
    );
    match enter_next_qsort_comparator(uc, &mut state) {
        QsortStep::ComparatorEntered => {}
        QsortStep::Done => return finish_qsort_callout(uc, state),
        QsortStep::Failed => return false,
    }
    pending_returns.borrow_mut().push(state);
    true
}

#[cfg(feature = "unicorn")]
fn handle_qsort_return_stub<D>(
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingQsortReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    let mut pending = pending_returns.borrow_mut();
    let Some(state) = pending.last_mut() else {
        return false;
    };
    let result = read_mips_reg(uc, RegisterMIPS::V0) as i32;
    let Some((left, right)) = state.current_pair.take() else {
        return false;
    };
    if !advance_qsort_partition_after_compare(uc, state, left, right, result) {
        return false;
    }
    match enter_next_qsort_comparator(uc, state) {
        QsortStep::ComparatorEntered => true,
        QsortStep::Done => {
            let state = pending.pop().unwrap();
            finish_qsort_callout(uc, state)
        }
        QsortStep::Failed => false,
    }
}

#[cfg(feature = "unicorn")]
fn is_fsdmgr_test_file_lock_import(
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    name: Option<&str>,
) -> Option<bool> {
    if module_kind != crate::emulator::imports::ImportModuleKind::Fsdmgr {
        return None;
    }
    match ordinal {
        Some(33) => Some(false),
        Some(34) => Some(true),
        _ => match name {
            Some(name) if name.eq_ignore_ascii_case("FSDMGR_TestFileLock") => Some(false),
            Some(name) if name.eq_ignore_ascii_case("FSDMGR_TestFileLockEx") => Some(true),
            _ => None,
        },
    }
}

#[cfg(feature = "unicorn")]
fn is_fsdmgr_install_file_lock_import(
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    name: Option<&str>,
) -> bool {
    if module_kind != crate::emulator::imports::ImportModuleKind::Fsdmgr {
        return false;
    }
    matches!(ordinal, Some(23))
        || name.is_some_and(|name| name.eq_ignore_ascii_case("FSDMGR_InstallFileLock"))
}

#[cfg(feature = "unicorn")]
fn is_fsdmgr_remove_file_lock_ex_import(
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    name: Option<&str>,
) -> bool {
    if module_kind != crate::emulator::imports::ImportModuleKind::Fsdmgr {
        return false;
    }
    matches!(ordinal, Some(29))
        || name.is_some_and(|name| name.eq_ignore_ascii_case("FSDMGR_RemoveFileLockEx"))
}

#[cfg(feature = "unicorn")]
fn is_fsdmgr_remove_file_lock_import(
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    name: Option<&str>,
) -> bool {
    if module_kind != crate::emulator::imports::ImportModuleKind::Fsdmgr {
        return false;
    }
    matches!(ordinal, Some(28))
        || name.is_some_and(|name| name.eq_ignore_ascii_case("FSDMGR_RemoveFileLock"))
}

#[cfg(feature = "unicorn")]
fn try_enter_fsdmgr_file_lock_callout<D>(
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    name: Option<&str>,
    args: &[u32],
    pending_returns: &std::rc::Rc<std::cell::RefCell<Vec<PendingFsdmgrFileLockReturn>>>,
) -> bool {
    use unicorn_engine::RegisterMIPS;

    let test_lock_import = is_fsdmgr_test_file_lock_import(module_kind, ordinal, name);
    let install_import = is_fsdmgr_install_file_lock_import(module_kind, ordinal, name);
    let remove_exact_import = is_fsdmgr_remove_file_lock_import(module_kind, ordinal, name);
    if test_lock_import.is_none()
        && !install_import
        && !remove_exact_import
        && !is_fsdmgr_remove_file_lock_ex_import(module_kind, ordinal, name)
    {
        return false;
    }
    let acquire_callback = args.first().copied().unwrap_or(0);
    let release_callback = args.get(1).copied().unwrap_or(0);
    if !is_guest_wndproc(acquire_callback) || !is_guest_wndproc(release_callback) {
        return false;
    }
    let file_handle = args.get(2).copied().unwrap_or(0);
    let operation = match test_lock_import {
        Some(has_explicit_offset) => {
            let read = args.get(3).copied().unwrap_or(0) != 0;
            let length_low = args.get(4).copied().unwrap_or(0);
            let explicit_offset = has_explicit_offset.then(|| {
                (
                    args.get(5).copied().unwrap_or(0),
                    args.get(6).copied().unwrap_or(0),
                )
            });
            FsdmgrFileLockOperation::Test {
                read,
                length_low,
                explicit_offset,
            }
        }
        None if install_import => FsdmgrFileLockOperation::Install {
            flags: args.get(3).copied().unwrap_or(0),
            length_low: args.get(5).copied().unwrap_or(0),
            length_high: args.get(6).copied().unwrap_or(0),
            overlapped_ptr: args.get(7).copied().unwrap_or(0),
        },
        None if remove_exact_import => FsdmgrFileLockOperation::RemoveExact {
            length_low: args.get(4).copied().unwrap_or(0),
            length_high: args.get(5).copied().unwrap_or(0),
            overlapped_ptr: args.get(6).copied().unwrap_or(0),
        },
        None => FsdmgrFileLockOperation::RemoveAll,
    };
    let return_pc = read_mips_reg(uc, RegisterMIPS::RA);
    let return_sp = read_mips_reg(uc, RegisterMIPS::SP);
    let caller_regs = capture_mips_gprs(uc);
    let call_sp = return_sp.wrapping_sub(WNDPROC_CALL_FRAME_BYTES);
    if uc
        .mem_write(u64::from(call_sp), &0u32.to_le_bytes())
        .is_err()
    {
        return false;
    }

    let call_callback = normalize_ce_process_slot_callback(uc, acquire_callback);
    let ok = [
        uc.reg_write(RegisterMIPS::SP, u64::from(call_sp)),
        uc.reg_write(RegisterMIPS::A0, u64::from(file_handle)),
        uc.reg_write(RegisterMIPS::A1, u64::from(call_sp)),
        uc.reg_write(
            RegisterMIPS::RA,
            u64::from(FSDMGR_FILE_LOCK_RETURN_STUB_ADDR),
        ),
        uc.reg_write(RegisterMIPS::T9, u64::from(call_callback)),
        uc.reg_write(RegisterMIPS::PC, u64::from(call_callback)),
    ]
    .into_iter()
    .all(|write| write.is_ok());
    if !ok {
        return false;
    }

    pending_returns
        .borrow_mut()
        .push(PendingFsdmgrFileLockReturn {
            phase: FsdmgrFileLockPhase::Acquire,
            return_pc,
            return_sp,
            caller_regs,
            operation,
            release_callback,
            file_handle,
            file_lock_state_ptr_slot: call_sp,
            api_result: 0,
        });
    true
}

#[cfg(feature = "unicorn")]
fn read_unicorn_u32_result<D>(uc: &unicorn_engine::Unicorn<'_, D>, address: u32) -> Option<u32> {
    let mut bytes = [0u8; 4];
    uc.mem_read(u64::from(address), &mut bytes).ok()?;
    Some(u32::from_le_bytes(bytes))
}

#[cfg(feature = "unicorn")]
fn write_unicorn_u32_result<D>(
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    address: u32,
    value: u32,
) -> bool {
    uc.mem_write(u64::from(address), &value.to_le_bytes())
        .is_ok()
}

#[cfg(feature = "unicorn")]
fn fsdmgr_guest_file_lock_test_result<D>(
    kernel: &mut CeKernel,
    uc: &unicorn_engine::Unicorn<'_, D>,
    thread_id: u32,
    state: &PendingFsdmgrFileLockReturn,
) -> u32 {
    const ERROR_INVALID_HANDLE: u32 = 6;
    const ERROR_INVALID_PARAMETER: u32 = 87;
    const ERROR_LOCK_VIOLATION: u32 = 33;
    const FILE_LOCK_STATE_POS_LOW_OFFSET: u32 = 0;
    const FILE_LOCK_STATE_POS_HIGH_OFFSET: u32 = 4;
    const FILE_LOCK_STATE_LOCK_CONTAINER_OFFSET: u32 = 28;
    let FsdmgrFileLockOperation::Test {
        read,
        length_low,
        explicit_offset,
    } = state.operation
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };

    let Some(file_lock_state_ptr) = read_unicorn_u32_result(uc, state.file_lock_state_ptr_slot)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if file_lock_state_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(lock_container) = read_unicorn_u32_result(
        uc,
        file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_LOCK_CONTAINER_OFFSET),
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if lock_container == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return 1;
    }
    let (offset_low, offset_high) = match explicit_offset {
        Some(offset) => offset,
        None => {
            let Some(low) = read_unicorn_u32_result(
                uc,
                file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_POS_LOW_OFFSET),
            ) else {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return 0;
            };
            let Some(high) = read_unicorn_u32_result(
                uc,
                file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_POS_HIGH_OFFSET),
            ) else {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return 0;
            };
            (low, high)
        }
    };
    let start = u64::from(offset_low) | (u64::from(offset_high) << 32);
    match kernel.test_file_lock_range(state.file_handle, start, u64::from(length_low), read) {
        Ok(FileLockStatus::Success) => {
            kernel.threads.set_last_error(thread_id, 0);
            1
        }
        Ok(FileLockStatus::Conflict) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_LOCK_VIOLATION);
            0
        }
        Ok(FileLockStatus::InvalidParameter) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            0
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            0
        }
    }
}

#[cfg(feature = "unicorn")]
fn fsdmgr_guest_install_file_lock_result<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    thread_id: u32,
    state: &PendingFsdmgrFileLockReturn,
) -> u32 {
    const ERROR_INVALID_HANDLE: u32 = 6;
    const ERROR_INVALID_PARAMETER: u32 = 87;
    const ERROR_LOCK_VIOLATION: u32 = 33;
    const FILE_GENERIC_READ: u32 = 0x8000_0000;
    const FILE_GENERIC_WRITE: u32 = 0x4000_0000;
    const LOCKFILE_EXCLUSIVE_LOCK: u32 = 0x0000_0002;
    const SYNTHETIC_LOCK_CONTAINER: u32 = 1;
    const FILE_LOCK_STATE_ACCESS_OFFSET: u32 = 8;
    const FILE_LOCK_STATE_FTERMINAL_OFFSET: u32 = 16;
    const FILE_LOCK_STATE_LOCK_CONTAINER_OFFSET: u32 = 28;
    let FsdmgrFileLockOperation::Install {
        flags,
        length_low,
        length_high,
        overlapped_ptr,
    } = state.operation
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };

    let Some(file_lock_state_ptr) = read_unicorn_u32_result(uc, state.file_lock_state_ptr_slot)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if file_lock_state_ptr == 0 || overlapped_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(terminal) = read_unicorn_u32_result(
        uc,
        file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_FTERMINAL_OFFSET),
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if terminal != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(access) = read_unicorn_u32_result(
        uc,
        file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_ACCESS_OFFSET),
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if access & (FILE_GENERIC_READ | FILE_GENERIC_WRITE) == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }

    let lock_container_ptr =
        file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_LOCK_CONTAINER_OFFSET);
    let Some(lock_container) = read_unicorn_u32_result(uc, lock_container_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if lock_container == 0
        && !write_unicorn_u32_result(uc, lock_container_ptr, SYNTHETIC_LOCK_CONTAINER)
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }

    let mut overlapped = [0u8; 20];
    if uc
        .mem_read(u64::from(overlapped_ptr), &mut overlapped)
        .is_err()
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let start_low = u32::from_le_bytes(overlapped[8..12].try_into().unwrap());
    let start_high = u32::from_le_bytes(overlapped[12..16].try_into().unwrap());
    let start = u64::from(start_low) | (u64::from(start_high) << 32);
    let length = u64::from(length_low) | (u64::from(length_high) << 32);
    match kernel.lock_file_range(
        state.file_handle,
        start,
        length,
        flags & LOCKFILE_EXCLUSIVE_LOCK != 0,
    ) {
        Ok(FileLockStatus::Success) => {
            kernel.threads.set_last_error(thread_id, 0);
            1
        }
        Ok(FileLockStatus::Conflict) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_LOCK_VIOLATION);
            0
        }
        Ok(FileLockStatus::InvalidParameter) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            0
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            0
        }
    }
}

#[cfg(feature = "unicorn")]
fn fsdmgr_guest_remove_file_lock_ex_result<D>(
    kernel: &mut CeKernel,
    uc: &mut unicorn_engine::Unicorn<'_, D>,
    thread_id: u32,
    state: &PendingFsdmgrFileLockReturn,
) -> u32 {
    const ERROR_INVALID_HANDLE: u32 = 6;
    const ERROR_INVALID_PARAMETER: u32 = 87;
    const ERROR_LOCK_VIOLATION: u32 = 33;
    const FILE_LOCK_STATE_CQUEUE_OFFSET: u32 = 24;
    const FILE_LOCK_STATE_LOCK_CONTAINER_OFFSET: u32 = 28;

    let Some(file_lock_state_ptr) = read_unicorn_u32_result(uc, state.file_lock_state_ptr_slot)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if file_lock_state_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let lock_container_ptr =
        file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_LOCK_CONTAINER_OFFSET);
    let Some(lock_container) = read_unicorn_u32_result(uc, lock_container_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if lock_container == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return 1;
    }

    match kernel.unlock_file_ranges_owned_by_handle(state.file_handle) {
        Ok(FileLockStatus::Success) => {}
        Ok(FileLockStatus::Conflict) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_LOCK_VIOLATION);
            return 0;
        }
        Ok(FileLockStatus::InvalidParameter) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        }
    }

    let Some(queue_count) = read_unicorn_u32_result(
        uc,
        file_lock_state_ptr.wrapping_add(FILE_LOCK_STATE_CQUEUE_OFFSET),
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if queue_count == 0 {
        match kernel.file_handle_has_locks(state.file_handle) {
            Ok(false) => {
                if !write_unicorn_u32_result(uc, lock_container_ptr, 0) {
                    kernel
                        .threads
                        .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                    return 0;
                }
            }
            Ok(true) => {}
            Err(_) => {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return 0;
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    1
}

