#[cfg(feature = "unicorn")]
fn append_unicorn_message_detail(
    parts: &mut Vec<String>,
    prefix: &str,
    message: &UnicornMessageRecord,
) {
    parts.push(format!("{prefix}_hwnd=0x{:08x}", message.hwnd));
    parts.push(format!("{prefix}_msg=0x{:04x}", message.msg));
    parts.push(format!("{prefix}_wparam=0x{:08x}", message.wparam));
    parts.push(format!("{prefix}_lparam=0x{:08x}", message.lparam));
    parts.push(format!("{prefix}_time={}", message.time_ms));
    if let Some(detail) = message.detail.as_deref() {
        parts.push(format!("{prefix}_detail={detail}"));
    }
}

#[cfg(feature = "unicorn")]
fn decode_message_record_detail(message: &crate::ce::gwe::Message) -> Option<String> {
    if message.msg != crate::ce::gwe::WM_WINDOWPOSCHANGED {
        return None;
    }
    Some(format!("WINDOWPOS_PAYLOAD lparam=0x{:08x}", message.lparam))
}

#[cfg(feature = "unicorn")]
fn import_resource_arg_detail<D>(uc: &unicorn_engine::Unicorn<'_, D>, ptr: u32) -> String {
    import_pointer_or_wide_arg(uc, ptr)
        .map(|value| format!("{value:?}"))
        .unwrap_or_else(|| format!("0x{ptr:08x}"))
}

#[cfg(feature = "unicorn")]
fn import_pointer_or_wide_arg<D>(uc: &unicorn_engine::Unicorn<'_, D>, ptr: u32) -> Option<String> {
    if ptr == 0 {
        return None;
    }
    if ptr <= 0xffff {
        return Some(format!("#{ptr}"));
    }
    read_unicorn_wide_z(uc, ptr, 128)
}

#[cfg(feature = "unicorn")]
fn import_dc_detail(kernel: &CeKernel, prefix: &str, hdc: u32) -> String {
    let synthetic_hwnd = if hdc & 0xff00_0000 == 0x0200_0000 {
        hdc & 0x00ff_ffff
    } else {
        0
    };
    let selected_bitmap = kernel.resources.selected_bitmap(hdc).unwrap_or(0);
    let mut parts = vec![
        format!("{prefix}_memdc={}", kernel.resources.is_memory_dc(hdc)),
        format!("{prefix}_hwnd=0x{synthetic_hwnd:08x}"),
        format!("{prefix}_selected_bitmap=0x{selected_bitmap:08x}"),
        import_bitmap_detail(
            kernel,
            &format!("{prefix}_selected_bitmap"),
            selected_bitmap,
        ),
        import_bitmap_detail(kernel, &format!("{prefix}_handle_bitmap"), hdc),
    ];
    if let Some(clip) = kernel.resources.clip_region(hdc) {
        parts.push(format!(
            "{prefix}_clip_rects={}/bbox={},{}-{},{}",
            clip.rects.len(),
            clip.rect.left,
            clip.rect.top,
            clip.rect.right,
            clip.rect.bottom
        ));
    }
    parts.join("/")
}

#[cfg(feature = "unicorn")]
fn import_guest_points_bbox<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    points: u32,
    count: u32,
) -> String {
    if points == 0 || count == 0 {
        return "bbox=none".to_string();
    }
    let mut left = i32::MAX;
    let mut top = i32::MAX;
    let mut right = i32::MIN;
    let mut bottom = i32::MIN;
    let mut read = 0u32;
    for index in 0..count.min(512) {
        let ptr = points.wrapping_add(index.saturating_mul(8));
        let Some(x) = read_unicorn_u32(uc, ptr).map(|value| value as i32) else {
            break;
        };
        let Some(y) = read_unicorn_u32(uc, ptr.wrapping_add(4)).map(|value| value as i32) else {
            break;
        };
        left = left.min(x);
        top = top.min(y);
        right = right.max(x);
        bottom = bottom.max(y);
        read += 1;
    }
    if read == 0 {
        "bbox=unreadable".to_string()
    } else {
        format!("bbox={left},{top}-{right},{bottom}/points_read={read}")
    }
}

#[cfg(feature = "unicorn")]
fn import_bitmap_detail(kernel: &CeKernel, prefix: &str, bitmap: u32) -> String {
    let Some(bitmap) = kernel.resources.bitmap(bitmap) else {
        return format!("{prefix}_detail=none");
    };
    format!(
        "{prefix}_detail={}:{}x{}x{}:stride={}:bits=0x{:08x}:owned={}",
        if bitmap.top_down {
            "top-down"
        } else {
            "bottom-up"
        },
        bitmap.width,
        bitmap.height,
        bitmap.bits_pixel,
        bitmap.width_bytes,
        bitmap.bits_ptr,
        bitmap.bits_owned
    )
}

#[cfg(feature = "unicorn")]
fn import_gdi_object_detail(kernel: &CeKernel, handle: u32) -> String {
    if handle == 0 {
        return "none".to_owned();
    }
    if let Some(brush) = kernel.resources.brush(handle) {
        return match brush.pattern_bitmap {
            Some(bitmap) => format!(
                "brush:pattern=0x{bitmap:08x}:{}",
                import_bitmap_detail(kernel, "pattern", bitmap)
            ),
            None => format!("brush:solid=0x{:06x}", brush.color & 0x00ff_ffff),
        };
    }
    if let Some(pen) = kernel.resources.pen(handle) {
        return format!(
            "pen:style={}:width={}:color=0x{:06x}",
            pen.style,
            pen.width,
            pen.color & 0x00ff_ffff
        );
    }
    if kernel.resources.bitmap(handle).is_some() {
        return format!("bitmap:{}", import_bitmap_detail(kernel, "bitmap", handle));
    }
    for (index, name) in [
        (0, "WHITE_BRUSH"),
        (1, "LTGRAY_BRUSH"),
        (2, "GRAY_BRUSH"),
        (3, "DKGRAY_BRUSH"),
        (4, "BLACK_BRUSH"),
        (5, "NULL_BRUSH"),
        (6, "WHITE_PEN"),
        (7, "BLACK_PEN"),
        (8, "NULL_PEN"),
        (13, "SYSTEM_FONT"),
        (15, "DEFAULT_PALETTE"),
        (18, "DC_BRUSH"),
        (19, "DC_PEN"),
    ] {
        if crate::ce::resource::stock_object_handle(index) == Some(handle) {
            return format!("stock:{name}");
        }
    }
    "unknown".to_owned()
}

#[cfg(feature = "unicorn")]
fn read_paint_struct_rect<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    paint_ptr: u32,
) -> Option<crate::ce::gwe::Rect> {
    (paint_ptr != 0).then(|| crate::ce::gwe::Rect {
        left: read_unicorn_u32(uc, paint_ptr.wrapping_add(8)).unwrap_or(0) as i32,
        top: read_unicorn_u32(uc, paint_ptr.wrapping_add(12)).unwrap_or(0) as i32,
        right: read_unicorn_u32(uc, paint_ptr.wrapping_add(16)).unwrap_or(0) as i32,
        bottom: read_unicorn_u32(uc, paint_ptr.wrapping_add(20)).unwrap_or(0) as i32,
    })
}

#[cfg(feature = "unicorn")]
fn read_unicorn_wide_z<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    ptr: u32,
    max_units: usize,
) -> Option<String> {
    if ptr == 0 {
        return None;
    }
    let mut units = Vec::new();
    for index in 0..max_units {
        let addr = ptr.wrapping_add((index as u32).wrapping_mul(2));
        let mut bytes = [0u8; 2];
        uc.mem_read(u64::from(addr), &mut bytes).ok()?;
        let unit = u16::from_le_bytes(bytes);
        if unit == 0 {
            break;
        }
        units.push(unit);
    }
    String::from_utf16(&units).ok()
}

#[cfg(feature = "unicorn")]
fn read_unicorn_narrow_z<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    ptr: u32,
    max_bytes: usize,
) -> Option<String> {
    if ptr == 0 {
        return None;
    }
    let mut bytes = Vec::new();
    for index in 0..max_bytes {
        let addr = ptr.wrapping_add(index as u32);
        let mut byte = [0u8; 1];
        uc.mem_read(u64::from(addr), &mut byte).ok()?;
        if byte[0] == 0 {
            break;
        }
        bytes.push(byte[0]);
    }
    Some(String::from_utf8_lossy(&bytes).into_owned())
}

#[cfg(feature = "unicorn")]
fn read_unicorn_bytes_preview<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    ptr: u32,
    max_bytes: usize,
) -> Option<String> {
    if ptr == 0 || max_bytes == 0 {
        return None;
    }
    let mut bytes = vec![0u8; max_bytes];
    uc.mem_read(u64::from(ptr), &mut bytes).ok()?;
    let mut preview = String::new();
    for byte in bytes {
        match byte {
            b'\r' => preview.push_str("\\r"),
            b'\n' => preview.push_str("\\n"),
            b'\t' => preview.push_str("\\t"),
            0x20..=0x7e => preview.push(byte as char),
            _ => preview.push_str(&format!("\\x{byte:02x}")),
        }
    }
    Some(preview)
}

#[cfg(all(feature = "unicorn", feature = "trace"))]
fn resource_pointer_preview<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    ptr: u32,
    max_units: usize,
) -> String {
    let mut parts = vec![format!("ptr=0x{ptr:08x}")];
    if let Some(wide) = read_unicorn_wide_z(uc, ptr, max_units) {
        parts.push(format!("wide={wide:?}"));
    }
    if let Some(narrow) = read_unicorn_narrow_z(uc, ptr, max_units.saturating_mul(2)) {
        parts.push(format!("narrow={narrow:?}"));
    }
    if let Some(deref) = read_unicorn_u32(uc, ptr) {
        parts.push(format!("deref=0x{deref:08x}"));
        if let Some(wide) = read_unicorn_wide_z(uc, deref, max_units) {
            parts.push(format!("deref_wide={wide:?}"));
        }
        if let Some(narrow) = read_unicorn_narrow_z(uc, deref, max_units.saturating_mul(2)) {
            parts.push(format!("deref_narrow={narrow:?}"));
        }
    }
    parts.join("/")
}

#[cfg(all(feature = "unicorn", feature = "trace"))]
fn resource_lookup_table_snapshot<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    state_ptr: u32,
) -> String {
    const TABLE_PTR: u32 = 0x0079_c440;

    let buffer = read_unicorn_u32(uc, TABLE_PTR).unwrap_or_default();
    let tree_root = read_unicorn_u32(uc, TABLE_PTR.wrapping_add(0x0c)).unwrap_or_default();
    let tree_count = read_unicorn_u32(uc, TABLE_PTR.wrapping_add(0x18)).unwrap_or_default();
    let mut parts = vec![
        format!("state=0x{state_ptr:08x}"),
        format!(
            "state_mode={}",
            read_unicorn_i16(uc, state_ptr).unwrap_or_default()
        ),
        format!(
            "state_submode={}",
            read_unicorn_i16(uc, state_ptr.wrapping_add(2)).unwrap_or_default()
        ),
        format!(
            "state_ready={}",
            read_unicorn_u8(uc, state_ptr.wrapping_add(0x20c)).unwrap_or_default()
        ),
        format!(
            "state_path={}",
            resource_pointer_preview(uc, state_ptr.wrapping_add(4), 260)
        ),
        format!("table=0x{TABLE_PTR:08x}"),
        format!("buffer=0x{buffer:08x}"),
        format!("tree_root=0x{tree_root:08x}"),
        format!("tree_count={tree_count}"),
        format!("table_words={}", resource_words_preview(uc, TABLE_PTR, 8)),
    ];

    if buffer != 0 {
        parts.push(format!(
            "buffer_header={}",
            resource_words_preview(uc, buffer, 4)
        ));
        parts.push(format!(
            "buffer_bytes={}",
            read_unicorn_bytes_preview(uc, buffer, 32).unwrap_or_else(|| "<unreadable>".to_owned())
        ));
    }
    if tree_root != 0 {
        parts.push(format!(
            "root_words={}",
            resource_words_preview(uc, tree_root, 8)
        ));
        parts.push(format!(
            "root_halfwords={}",
            resource_halfwords_preview(uc, tree_root, 16)
        ));
        for offset in [0x00, 0x04, 0x08, 0x0c, 0x10, 0x14, 0x18, 0x1c] {
            if let Some(ptr) = read_unicorn_u32(uc, tree_root.wrapping_add(offset))
                && ptr != 0
                && ptr != tree_root
            {
                parts.push(format!(
                    "root+0x{offset:02x}=0x{ptr:08x}:{}",
                    resource_halfwords_preview(uc, ptr, 8)
                ));
            }
        }
    }

    parts.join("/")
}

#[cfg(all(feature = "unicorn", feature = "trace"))]
fn resource_words_preview<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    ptr: u32,
    count: usize,
) -> String {
    (0..count)
        .map(|index| {
            let addr = ptr.wrapping_add((index * 4) as u32);
            read_unicorn_u32(uc, addr)
                .map(|value| format!("0x{value:08x}"))
                .unwrap_or_else(|| "<?>".to_owned())
        })
        .collect::<Vec<_>>()
        .join(",")
}

#[cfg(all(feature = "unicorn", feature = "trace"))]
fn resource_halfwords_preview<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    ptr: u32,
    count: usize,
) -> String {
    (0..count)
        .map(|index| {
            let addr = ptr.wrapping_add((index * 2) as u32);
            read_unicorn_i16(uc, addr)
                .map(|value| value.to_string())
                .unwrap_or_else(|| "<?>".to_owned())
        })
        .collect::<Vec<_>>()
        .join(",")
}

#[cfg(all(feature = "unicorn", feature = "trace"))]
fn cstring_wide_preview<D>(
    uc: &unicorn_engine::Unicorn<'_, D>,
    object_ptr: u32,
    max_units: usize,
) -> String {
    let mut parts = vec![format!("obj=0x{object_ptr:08x}")];
    let Some(data_ptr) = read_unicorn_u32(uc, object_ptr) else {
        parts.push("data=<unreadable>".to_owned());
        return parts.join("/");
    };
    parts.push(format!("data=0x{data_ptr:08x}"));
    if data_ptr != 0 {
        parts.push(format!(
            "len={}",
            read_unicorn_u32(uc, data_ptr.wrapping_sub(8)).unwrap_or_default()
        ));
        parts.push(format!(
            "alloc={}",
            read_unicorn_u32(uc, data_ptr.wrapping_sub(4)).unwrap_or_default()
        ));
        if let Some(wide) = read_unicorn_wide_z(uc, data_ptr, max_units) {
            parts.push(format!("wide={wide:?}"));
        }
        if let Some(narrow) = read_unicorn_narrow_z(uc, data_ptr, max_units.saturating_mul(2)) {
            parts.push(format!("narrow={narrow:?}"));
        }
    }
    parts.join("/")
}

fn format_trace_string(value: &str) -> String {
    format!("{value:?}")
}

fn format_optional_hwnd(hwnd: Option<u32>) -> String {
    hwnd.map(|hwnd| format!("0x{hwnd:08x}"))
        .unwrap_or_else(|| "<none>".to_owned())
}

fn write_unicorn_import_records(
    f: &mut std::fmt::Formatter<'_>,
    imports: &[UnicornLastImport],
) -> std::fmt::Result {
    for (index, import) in imports.iter().enumerate() {
        if index != 0 {
            write!(f, ",")?;
        }
        write!(f, "0x{:08x}/{:?}/{}", import.pc, import.kind, import.module)?;
        if let Some(ordinal) = import.ordinal {
            write!(f, "/ord={ordinal}")?;
        }
        if let Some(name) = import.name.as_deref() {
            write!(f, "/name={name}")?;
        }
        write!(
            f,
            "/ra=0x{:08x}/a0=0x{:08x}/a1=0x{:08x}/a2=0x{:08x}/a3=0x{:08x}/sp=0x{:08x}",
            import.ra, import.a0, import.a1, import.a2, import.a3, import.sp
        )?;
        if let Some(result) = import.result {
            write!(f, "/ret=0x{result:08x}")?;
        } else {
            write!(f, "/ret=<pending>")?;
        }
        if let Some(detail) = import.detail.as_deref() {
            write!(f, "/detail={}", format_trace_string(detail))?;
        }
    }
    Ok(())
}

fn write_file_trace_records(
    f: &mut std::fmt::Formatter<'_>,
    records: &[crate::ce::kernel::FileTraceRecord],
) -> std::fmt::Result {
    for (index, op) in records.iter().enumerate() {
        if index != 0 {
            write!(f, ",")?;
        }
        write!(f, "{}", op.op)?;
        if let Some(handle) = op.handle {
            write!(f, "/h=0x{handle:08x}")?;
        }
        if let Some(path) = op.path.as_deref() {
            write!(f, "/path={}", format_trace_string(path))?;
        }
        if let Some(preview) = op.preview.as_deref() {
            write!(f, "/preview={}", format_trace_string(preview))?;
        }
        if let Some(requested) = op.requested {
            write!(f, "/req=0x{requested:08x}")?;
        }
        if let Some(transferred) = op.transferred {
            write!(f, "/xfer=0x{transferred:08x}")?;
        }
        if let Some(position) = op.position {
            write!(f, "/pos=0x{position:08x}")?;
        }
        if let Some(result) = op.result {
            write!(f, "/ret=0x{result:08x}")?;
        }
        if let Some(error) = op.error.as_deref() {
            write!(f, "/err={}", format_trace_string(error))?;
        }
    }
    Ok(())
}

fn write_process_trace_records(
    f: &mut std::fmt::Formatter<'_>,
    records: &[crate::ce::kernel::ProcessTraceRecord],
) -> std::fmt::Result {
    for (index, op) in records.iter().enumerate() {
        if index != 0 {
            write!(f, ",")?;
        }
        write!(f, "{}", op.op)?;
        if let Some(application) = op.application.as_deref() {
            write!(f, "/app={}", format_trace_string(application))?;
        }
        if let Some(command_line) = op.command_line.as_deref() {
            write!(f, "/cmd={}", format_trace_string(command_line))?;
        }
        if let Some(path) = op.path.as_deref() {
            write!(f, "/path={}", format_trace_string(path))?;
        }
        if let Some(handle) = op.process_handle {
            write!(f, "/process=0x{handle:08x}")?;
        }
        if let Some(handle) = op.thread_handle {
            write!(f, "/thread=0x{handle:08x}")?;
        }
        if let Some(process_id) = op.process_id {
            write!(f, "/pid={process_id}")?;
        }
        if let Some(thread_id) = op.thread_id {
            write!(f, "/tid={thread_id}")?;
        }
        if let Some(result) = op.result {
            write!(f, "/ret=0x{result:08x}")?;
        }
        if let Some(error) = op.error.as_deref() {
            write!(f, "/err={}", format_trace_string(error))?;
        }
    }
    Ok(())
}

#[cfg(feature = "unicorn")]
fn trace_import_name(
    module_kind: crate::emulator::imports::ImportModuleKind,
    ordinal: Option<u32>,
    name: Option<&str>,
) -> Option<String> {
    if let Some(name) = name {
        return Some(name.to_owned());
    }
    if module_kind != crate::emulator::imports::ImportModuleKind::Coredll {
        return None;
    }
    crate::ce::coredll_ordinals::lookup(ordinal?).map(|export| export.name.to_owned())
}

