    #[test]
    fn shell_notification_com_dispatch_restores_unmapped_callback_pointer() {
        use crate::ce::shell::{ShellNotificationCallbackMethod, ShellNotificationCallbackRecord};

        let mut uc = Unicorn::new(Arch::MIPS, Mode::MIPS32 | Mode::LITTLE_ENDIAN).unwrap();
        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = CeKernel::boot(config);
        let method = ShellNotificationCallbackMethod::OnDismiss { timed_out: true };
        let callback = ShellNotificationCallbackRecord {
            clsid: [0x42; 16],
            id: 77,
            vtable_offset: method.com_vtable_offset(),
            arguments: method.com_arguments(77, 0x1234_5678),
            method,
            lparam: 0x1234_5678,
            callback_ptr: 0x3000_4000,
        };
        kernel.shell.record_notification_callback(callback.clone());
        let pending = Rc::new(RefCell::new(Vec::new()));

        assert!(!super::try_dispatch_com_notification_callout(
            &mut kernel,
            &mut uc,
            0x8000_1000,
            &pending,
        ));
        assert!(pending.borrow().is_empty());
        assert_eq!(
            kernel.shell.take_pending_notification_callback(),
            Some(callback),
            "unmapped non-null callback pointers should be retried before newer notifications"
        );
    }

    #[test]
    fn shell_notification_com_dispatch_enters_mapped_guest_callback() {
        use crate::ce::shell::{ShellNotificationCallbackMethod, ShellNotificationCallbackRecord};

        let mut uc = Unicorn::new(Arch::MIPS, Mode::MIPS32 | Mode::LITTLE_ENDIAN).unwrap();
        uc.mem_map(0x3000_0000, 0x2000, Prot::ALL).unwrap();

        let callback_ptr = 0x3000_0100u32;
        let vtable_ptr = 0x3000_0200u32;
        let method_ptr = 0x0040_1000u32;
        uc.mem_write(u64::from(callback_ptr), &vtable_ptr.to_le_bytes())
            .unwrap();
        uc.mem_write(
            u64::from(
                vtable_ptr
                    + crate::ce::shell::ISHELL_NOTIFICATION_CALLBACK_ON_DISMISS_VTABLE_OFFSET,
            ),
            &method_ptr.to_le_bytes(),
        )
        .unwrap();

        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = CeKernel::boot(config);
        let method = ShellNotificationCallbackMethod::OnDismiss { timed_out: true };
        kernel
            .shell
            .record_notification_callback(ShellNotificationCallbackRecord {
                clsid: [0x42; 16],
                id: 77,
                vtable_offset: method.com_vtable_offset(),
                arguments: method.com_arguments(77, 0x1234_5678),
                method,
                lparam: 0x1234_5678,
                callback_ptr,
            });

        let import_pc = 0x8000_1000;
        let return_sp = 0x3000_1800u32;
        uc.reg_write(RegisterMIPS::SP, u64::from(return_sp))
            .unwrap();
        uc.reg_write(RegisterMIPS::RA, 0x8000_2000).unwrap();
        let pending = Rc::new(RefCell::new(Vec::new()));

        assert!(super::try_dispatch_com_notification_callout(
            &mut kernel,
            &mut uc,
            import_pc,
            &pending,
        ));
        assert!(kernel.shell.take_pending_notification_callback().is_none());
        assert_eq!(uc.reg_read(RegisterMIPS::PC).unwrap() as u32, method_ptr);
        assert_eq!(uc.reg_read(RegisterMIPS::T9).unwrap() as u32, method_ptr);
        assert_eq!(
            uc.reg_read(RegisterMIPS::RA).unwrap() as u32,
            super::COM_NOTIFICATION_RETURN_STUB_ADDR
        );
        assert_eq!(
            uc.reg_read(RegisterMIPS::SP).unwrap() as u32,
            return_sp - super::WNDPROC_CALL_FRAME_BYTES
        );
        assert_eq!(uc.reg_read(RegisterMIPS::A0).unwrap() as u32, callback_ptr);
        assert_eq!(uc.reg_read(RegisterMIPS::A1).unwrap() as u32, 77);
        assert_eq!(uc.reg_read(RegisterMIPS::A2).unwrap() as u32, 1);
        assert_eq!(uc.reg_read(RegisterMIPS::A3).unwrap() as u32, 0x1234_5678);

        let pending = pending.borrow();
        assert_eq!(pending.len(), 1);
        assert_eq!(pending[0].return_pc, import_pc);
        assert_eq!(pending[0].return_sp, return_sp);
        assert_eq!(pending[0].heap_ptr_to_free, None);
    }

    #[test]
    fn runtime_loader_failure_rollback_releases_only_new_modules() {
        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = CeKernel::boot(config);
        let dynamic = crate::ce::kernel::LoadedModuleMetadata {
            dynamic: true,
            ..Default::default()
        };
        kernel.register_loaded_module_with_metadata(
            "already.dll",
            0x7100_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            dynamic.clone(),
        );
        kernel.register_loaded_module_with_metadata(
            "dependency.dll",
            0x7200_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            dynamic.clone(),
        );
        kernel.register_loaded_module_with_metadata(
            "failed.dll",
            0x7300_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            dynamic,
        );

        assert_eq!(
            super::rollback_runtime_loader_new_modules(
                &mut kernel,
                &[0x7200_0000, 0x7300_0000, 0x7200_0000],
            ),
            2
        );

        assert_eq!(
            kernel.loaded_module_handle("already.dll"),
            Some(0x7100_0000)
        );
        assert_eq!(kernel.loaded_module_handle("dependency.dll"), None);
        assert_eq!(kernel.loaded_module_handle("failed.dll"), None);
        let snapshots = kernel.loaded_module_snapshots();
        assert!(
            snapshots
                .iter()
                .any(|module| module.name == "already.dll" && !module.unload_pending)
        );
        assert!(
            snapshots
                .iter()
                .any(|module| module.name == "dependency.dll" && module.unload_pending)
        );
        assert!(
            snapshots
                .iter()
                .any(|module| module.name == "failed.dll" && module.unload_pending)
        );
    }

    #[test]
    fn dll_attach_failure_releases_attempt_refs_and_sets_init_failed() {
        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = CeKernel::boot(config);
        kernel.register_loaded_module_with_metadata(
            "retained.dll",
            0x7100_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            crate::ce::kernel::LoadedModuleMetadata {
                ref_count: 2,
                dynamic: true,
                ..Default::default()
            },
        );
        kernel.register_loaded_module_with_metadata(
            "failed.dll",
            0x7200_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            crate::ce::kernel::LoadedModuleMetadata {
                dynamic: true,
                ..Default::default()
            },
        );

        let refs =
            super::runtime_loader_attach_failure_release_refs(&[0x7200_0000], &[0x7100_0000]);
        super::apply_dll_lifecycle_return_side_effects(&mut kernel, 7, 0, Vec::new(), refs);

        assert_eq!(
            kernel.threads.get_last_error(7),
            crate::ce::thread::ERROR_DLL_INIT_FAILED
        );
        assert_eq!(kernel.runtime_loader_stats().loud_failure_count, 1);
        assert_eq!(kernel.loaded_module_handle("failed.dll"), None);
        let retained = kernel.loaded_module_by_handle(0x7100_0000).unwrap();
        assert_eq!(retained.ref_count, 1);
        assert!(!retained.unload_pending);
    }

    #[test]
    fn runtime_loadlibraryex_accepts_altered_search_path_for_loaded_module() {
        let mut uc = Unicorn::new(Arch::MIPS, Mode::MIPS32 | Mode::LITTLE_ENDIAN).unwrap();
        uc.mem_map(0x3000_0000, 0x2000, Prot::ALL).unwrap();
        let name_ptr = 0x3000_0100u32;
        let name_bytes = "altered.dll"
            .encode_utf16()
            .chain(std::iter::once(0))
            .flat_map(u16::to_le_bytes)
            .collect::<Vec<_>>();
        uc.mem_write(u64::from(name_ptr), &name_bytes).unwrap();

        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = CeKernel::boot(config);
        kernel.register_loaded_module_with_metadata(
            "altered.dll",
            0x7400_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            crate::ce::kernel::LoadedModuleMetadata {
                dynamic: true,
                ..Default::default()
            },
        );

        let trap = crate::emulator::imports::ImportTrap {
            address: 0x7fff_4000,
            module_kind: crate::emulator::imports::ImportModuleKind::Coredll,
            module_name: "coredll.dll".to_owned(),
            ordinal: Some(crate::ce::coredll_ordinals::ORD_LOAD_LIBRARY_EX_W),
            name: Some("LoadLibraryExW".to_owned()),
            iat_va: 0,
        };
        let mut memory_map = MemoryMap::default();
        let mut mapped_blobs = Vec::new();
        let mut loaded_modules = Vec::new();
        let mut resource_strings = Vec::new();
        let mut resources = Vec::new();
        let mut trampoline_ranges = Vec::new();
        let mut trampoline_jumps = Vec::new();
        let live_trampoline_state = Rc::new(RefCell::new(LiveTrampolineState::new_with_stub_map(
            Vec::new(),
            Vec::new(),
            HashMap::new(),
        )));
        let traps = Rc::new(RefCell::new(ImportTrapTable::new()));
        let pending = Rc::new(RefCell::new(Vec::new()));

        let result = super::try_handle_runtime_loader_import(
            &mut uc,
            &mut kernel,
            &mut memory_map,
            &mut mapped_blobs,
            &mut loaded_modules,
            &mut resource_strings,
            &mut resources,
            &mut trampoline_ranges,
            &mut trampoline_jumps,
            &live_trampoline_state,
            &traps,
            &[],
            7,
            &trap,
            &[name_ptr, 0, super::RUNTIME_LOAD_WITH_ALTERED_SEARCH_PATH],
            &pending,
        );

        assert!(matches!(
            result,
            Some(super::RuntimeLoaderImportResult::Complete(0x7400_0000))
        ));
        assert_eq!(kernel.threads.get_last_error(7), 0);
        assert_eq!(
            kernel
                .loaded_module_by_handle(0x7400_0000)
                .unwrap()
                .ref_count,
            2
        );
    }

    #[test]
    fn runtime_free_library_release_plan_releases_dependency_refs() {
        let config = RuntimeConfig::load_default().unwrap();
        let mut kernel = CeKernel::boot(config);
        kernel.register_loaded_module_with_metadata(
            "root.dll",
            0x7100_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            crate::ce::kernel::LoadedModuleMetadata {
                entry_point: 0x7100_1000,
                dependencies: vec!["dependency.dll".to_owned()],
                dynamic: true,
                ..Default::default()
            },
        );
        kernel.register_loaded_module_with_metadata(
            "dependency.dll",
            0x7200_0000,
            BTreeMap::new(),
            BTreeMap::new(),
            crate::ce::kernel::LoadedModuleMetadata {
                entry_point: 0x7200_1000,
                dynamic: true,
                ..Default::default()
            },
        );

        let root = kernel.loaded_module_by_handle(0x7100_0000).unwrap();
        let plan = super::runtime_free_library_release_plan(&kernel, &root);

        assert_eq!(
            plan.lifecycle_calls
                .iter()
                .map(|call| (call.module, call.target, call.reason, call.entrypoint))
                .collect::<Vec<_>>(),
            vec![
                (0x7100_0000, 0x7100_1000, super::DLL_PROCESS_DETACH, true),
                (0x7200_0000, 0x7200_1000, super::DLL_PROCESS_DETACH, true),
            ]
        );
        assert_eq!(plan.release_after_lifecycle, vec![0x7100_0000, 0x7200_0000]);
        assert_eq!(
            super::release_runtime_loader_module_refs(&mut kernel, plan.release_after_lifecycle,),
            2
        );
        assert_eq!(kernel.loaded_module_handle("root.dll"), None);
        assert_eq!(kernel.loaded_module_handle("dependency.dll"), None);
    }

