    #[test]
    fn wall_clock_restart_pc_restarts_mips_trampoline_before_delay_slot() {
        let origin = 0x0017_ee04;
        let stub = 0x009d_8900;
        let target = 0x0017_ee2c;
        let trampoline_jumps = [super::MipsTrampolineJump {
            origin,
            stub,
            byte_len: 0x20,
        }];

        assert_eq!(
            super::wall_clock_restart_pc_for_mips_trampoline(
                stub.wrapping_add(8),
                &trampoline_jumps,
                |_| None
            ),
            Some(origin)
        );
        assert_eq!(
            super::wall_clock_restart_pc_for_mips_trampoline(
                stub.wrapping_add(12),
                &trampoline_jumps,
                |addr| match addr {
                    // j 0x0017ee2c
                    value if value == stub.wrapping_add(12) => Some(0x0805_fb8b),
                    _ => None,
                }
            ),
            Some(target)
        );
        assert_eq!(
            super::wall_clock_restart_pc_for_mips_trampoline(origin, &trampoline_jumps, |_| None),
            None
        );
    }

    #[test]
    fn wall_clock_import_jr_thunk_resumes_at_import_trap() {
        let mut uc = Unicorn::new(Arch::MIPS, Mode::MIPS32 | Mode::LITTLE_ENDIAN).unwrap();
        let pc: u32 = 0x0040_0000;
        uc.mem_map(pc as u64, 0x1000, Prot::ALL).unwrap();
        uc.mem_write(u64::from(pc), &super::encode_mips_jr(8).to_le_bytes())
            .unwrap();
        uc.mem_write(
            u64::from(pc.wrapping_add(4)),
            &super::MIPS_NOP.to_le_bytes(),
        )
        .unwrap();

        let target = crate::emulator::imports::dynamic_coredll_proc_address(
            crate::ce::coredll_ordinals::ORD_MEMSET,
        )
        .unwrap();
        uc.reg_write(RegisterMIPS::T0, u64::from(target)).unwrap();

        assert_eq!(
            super::import_trap_target_for_mips_jr_thunk(
                &uc,
                &crate::emulator::imports::ImportTrapTable::new(),
                pc
            ),
            Some(target)
        );

        let static_import_target = crate::emulator::imports::IMPORT_TRAP_BASE + 0x3a60;
        uc.reg_write(RegisterMIPS::T0, u64::from(static_import_target))
            .unwrap();
        assert_eq!(
            super::import_trap_page_target_for_mips_jr_thunk(&uc, pc),
            Some(static_import_target)
        );
        assert_eq!(
            super::import_trap_target_for_mips_jr_thunk(
                &uc,
                &crate::emulator::imports::ImportTrapTable::new(),
                pc
            ),
            None
        );

        uc.mem_write(u64::from(pc.wrapping_add(4)), &0x2402_0001u32.to_le_bytes())
            .unwrap();
        assert_eq!(
            super::import_trap_target_for_mips_jr_thunk(
                &uc,
                &crate::emulator::imports::ImportTrapTable::new(),
                pc
            ),
            None
        );
    }

