    #[test]
    fn long_getmessage_timer_wait_respects_host_wall_budget() {
        let started = std::time::Instant::now();

        assert!(super::timer_delay_fits_host_wall_budget(
            7500, started, None
        ));
        assert!(super::timer_delay_fits_host_wall_budget(
            7500,
            started,
            Some(std::time::Duration::from_secs(30))
        ));
        assert!(!super::timer_delay_fits_host_wall_budget(
            7500,
            started,
            Some(std::time::Duration::from_millis(1))
        ));
        assert!(super::host_wall_budget_is_live_pump_slice(
            started,
            Some(std::time::Duration::from_millis(50))
        ));
        assert!(!super::host_wall_budget_is_live_pump_slice(
            started,
            Some(std::time::Duration::from_secs(1))
        ));
        assert!(!super::host_wall_budget_is_live_pump_slice(started, None));
        assert!(!super::timer_delay_can_sleep_in_host_hook(
            1,
            started,
            Some(std::time::Duration::from_secs(1)),
            true
        ));
        assert!(super::timer_delay_can_sleep_in_host_hook(
            1,
            started,
            Some(std::time::Duration::from_secs(1)),
            false
        ));
    }

